/* Appelé quand l'utilisateur clique "Accepter et continuer" */
function acceptCGU() {
  var checkbox = document.getElementById('cgu-checkbox');
  if (!checkbox.checked) return;

  /* Marque la CGU comme acceptée pour cet utilisateur */
  if (_verifyData) {
    var users = getUsers();
    var idx   = users.findIndex(function(u) {
      return u.email.toLowerCase() === _verifyData.email.toLowerCase();
    });
    if (idx !== -1) {
      users[idx].cguAccepted = true;
      saveUsers(users);
    }
    _verifyData = null;
  }

  /* _verifyEmail reste disponible même après _verifyData = null */
  var registeredEmail = _verifyEmail;

  /* ── Détection silencieuse du pays d'inscription (IP, sans popup) ── */
  if (registeredEmail) setTimeout(function() { _gwDetectRegCountry(registeredEmail); }, 1500);

  showToast('Bienvenue sur Geniwork ✓', 'ok');
  setTimeout(function() {
    var newUser = registeredEmail ? findUser(registeredEmail) : null;
    if (newUser) {
      var sessionUser = { nom: newUser.nom, email: newUser.email, loginMethod: newUser.loginMethod || 'email' };
      _currentUser = sessionUser;
      _gwCreateSession(sessionUser);
      /* Étape 2 migration auth : même principe que doLogin(), best-effort */
      if (_verifyPlainPwd) _gwSignInRealIdentity(newUser.email, _verifyPlainPwd);
      _verifyPlainPwd = '';
      initApp(sessionUser);
      scheduleNewPosts();
    }
    goTo('screen-app');
    setTimeout(_gwHandleDeepLink, 900);
  }, 1200);
}

/* ══════════════════════════════════════════
   LOCALISATION SILENCIEUSE — INSCRIPTION
   Détecte le pays via l'IP (aucun popup),
   stocke uniquement dans le profil admin
══════════════════════════════════════════ */
function _gwDetectRegCountry(email) {
  if (!email) return;
  /* Ne détecte qu'une fois — si déjà stocké, on skip */
  try {
    var _existing = loadUserProfile(email) || {};
    if (_existing.regCountry) return;
  } catch(e) {}

  fetch('https://ipapi.co/json/')
    .then(function(r) { return r.ok ? r.json() : null; })
    .then(function(data) {
      if (!data || !data.country_name) return;
      var cName = data.country_name || '';
      var cCode = (data.country || '').toUpperCase();
      var rDate = new Date().toISOString();

      /* ── Écriture Firebase (update — préserve tous les autres champs) ── */
      if (window._gwFbDB) {
        try {
          var fbKey = _gwFbKey(email);
          window._gwFbDB.ref('gw/profiles/' + fbKey).update({
            regCountry:     cName,
            regCountryCode: cCode,
            regDate:        rDate
          }).catch(function(){});
        } catch(e) {}
      }
      /* ── Mise à jour localStorage (sans déclencher la sync Firebase en boucle) ── */
      try {
        var _p = loadUserProfile(email) || {};
        if (!_p.regCountry) {
          _p.regCountry     = cName;
          _p.regCountryCode = cCode;
          _p.regDate        = rDate;
          localStorage.setItem('gw_profile_' + email, JSON.stringify(_p));
        }
      } catch(e) {}
    })
    .catch(function() { /* silencieux */ });
}

/* ══════════════════════════════════════════
   MOT DE PASSE OUBLIÉ
══════════════════════════════════════════ */
function doForgot() {
  var email = _gwSanitize(document.getElementById('forgot-email').value.trim().toLowerCase(), 320);

  if (!email || !email.includes('@')) {
    showToast('Adresse e-mail invalide', 'err'); return;
  }

  /* ── Compte banni → impossible de réinitialiser ── */
  var banInfo = _admGetBanInfo(email);
  if (banInfo) {
    goTo('screen-login');
    setTimeout(function() { _gwShowLoginBanScreen(email, banInfo); }, 150);
    return;
  }

  var user = findUser(email);

  /* Email non enregistré — message générique (sécurité) */
  if (!user) {
    showToast('Si ce compte existe, un code a été envoyé.', '');
    /* On simule quand même pour ne pas révéler si l'email existe */
    setTimeout(function() { goTo('screen-login'); }, 2000);
    return;
  }

  /* Génère le code de réinitialisation */
  _resetCode  = generateCode();
  _resetEmail = email;

  document.getElementById('reset-email-display').textContent = email;
  clearCodeInputs(['r1','r2','r3','r4']);

  goTo('screen-reset-verify');
  /* Envoie le code par e-mail */
  _gwMailCode(email, _resetCode, 'reset');
}

/* ══════════════════════════════════════════
   VÉRIFICATION CODE (reset)
══════════════════════════════════════════ */
function doResetVerify() {
  var entered = getCodeValue(['r1','r2','r3','r4']);

  if (entered.length < 4) {
    showToast('Entrez les 4 chiffres du code', 'err'); return;
  }
  if (entered !== _resetCode) {
    showToast('Code incorrect. Vérifiez et réessayez.', 'err');
    shakeCodeInputs(['r1','r2','r3','r4']); return;
  }

  /* Réinitialise les champs du nouveau mot de passe */
  document.getElementById('new-pwd').value  = '';
  document.getElementById('new-pwd2').value = '';
  updateRules('', 'rule2');

  goTo('screen-new-pwd');
}

function resendResetCode() {
  if (!_resetEmail) return;
  _resetCode = generateCode();
  clearCodeInputs(['r1','r2','r3','r4']);
  _gwMailCode(_resetEmail, _resetCode, 'reset');
}

/* ══════════════════════════════════════════
   ENREGISTRER NOUVEAU MOT DE PASSE
══════════════════════════════════════════ */
function doSaveNewPwd() {
  var pwd  = document.getElementById('new-pwd').value;
  var pwd2 = document.getElementById('new-pwd2').value;

  if (!isPasswordValid(pwd)) {
    showToast('Le mot de passe ne respecte pas les règles', 'err'); return;
  }
  if (pwd !== pwd2) {
    showToast('Les mots de passe ne correspondent pas', 'err'); return;
  }

  /* ── Compte banni → bloquer même si le code était valide ── */
  if (_resetEmail) {
    var banInfo = _admGetBanInfo(_resetEmail);
    if (banInfo) {
      var e = _resetEmail; _resetCode = ''; _resetEmail = '';
      goTo('screen-login');
      setTimeout(function() { _gwShowLoginBanScreen(e, banInfo); }, 150);
      return;
    }
  }

  /* ── Hache le nouveau mot de passe avant de sauvegarder ── */
  var salt = _gwSalt();
  _gwHashPwd(pwd, salt).then(function(hashed) {
    var users = getUsers();
    var idx   = users.findIndex(function(u) {
      return u.email.toLowerCase() === _resetEmail.toLowerCase();
    });
    if (idx !== -1) {
      users[idx].password = hashed;
      saveUsers(users);
    }

    /* Réinitialise aussi le brute-force pour cet email */
    _gwResetBrute('login:' + _resetEmail.toLowerCase());

    _resetCode  = '';
    _resetEmail = '';

    showToast('Mot de passe mis à jour ✓', 'ok');
    setTimeout(function() {
      goTo('screen-login');
    }, 1200);
  }).catch(function() {
    showToast('Erreur lors de la mise à jour. Réessayez.', 'err');
  });
}

/* ══════════════════════════════════════════
   UTILITAIRES CODE 4 CHIFFRES
══════════════════════════════════════════ */

/* Avance automatiquement au champ suivant */
function codeNext(input, nextId) {
  input.value = input.value.replace(/[^0-9]/g, '');
  if (input.value.length === 1) {
    input.classList.add('filled');
    if (nextId) {
      var next = document.getElementById(nextId);
      if (next) next.focus();
    }
  } else {
    input.classList.remove('filled');
  }
}

/* Retour arrière vers le champ précédent */
function codePrev(event, input, prevId) {
  if (event.key === 'Backspace' && input.value === '' && prevId) {
    var prev = document.getElementById(prevId);
    if (prev) { prev.focus(); prev.value = ''; prev.classList.remove('filled'); }
  }
}

/* Lit les 4 chiffres */
function getCodeValue(ids) {
  return ids.map(function(id) {
    return document.getElementById(id).value;
  }).join('');
}

/* Vide les 4 champs */
function clearCodeInputs(ids) {
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) { el.value = ''; el.classList.remove('filled'); }
  });
}

/* Animation secousse si code incorrect */
function shakeCodeInputs(ids) {
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    el.classList.add('shake');
    el.style.borderColor = '#EF4444';
    setTimeout(function() {
      el.classList.remove('shake');
      el.style.borderColor = '';
    }, 600);
  });
}

/* ══════════════════════════════════════════
   AFFICHER / CACHER MOT DE PASSE
══════════════════════════════════════════ */
function togglePwd(inputId, btn) {
  var input = document.getElementById(inputId);
  var icon  = btn.querySelector('i');
  if (input.type === 'password') {
    input.type     = 'text';
    icon.className = 'fas fa-eye-slash';
  } else {
    input.type     = 'password';
    icon.className = 'fas fa-eye';
  }
}

/* ══════════════════════════════════════════
   TOAST
══════════════════════════════════════════ */
var _toastTimer = null;
function showToast(message, type) {
  var el = document.getElementById('toast');
  el.textContent = message;
  el.className   = 'toast show' + (type ? ' ' + type : '');
  clearTimeout(_toastTimer);
  _toastTimer = setTimeout(function() {
    el.classList.remove('show');
  }, 3000);
}

/* ══════════════════════════════════════════
   APPLICATION — ÉTAT GLOBAL
══════════════════════════════════════════ */
var _currentUser = null;   /* utilisateur connecté */
var _currentPostId = null; /* post dont les commentaires sont ouverts */
var _feedTab = 'accueil';  /* onglet actif du feed */
var _pickedImgData = null; /* image choisie pour publier */

/* ══════════════════════════════════════════
   POSTS (chargés depuis Firebase / localStorage)
══════════════════════════════════════════ */
var DEMO_POSTS    = [];   /* Tous les posts réels — rempli au chargement */
var PENDING_POSTS = [];   /* Posts Firebase reçus en temps réel — vidé à l'acceptation */

/* ══════════════════════════════════════════
   INITIALISATION DE L'APPLICATION
══════════════════════════════════════════ */
/* ── Purge one-shot des données injectées par l'ancien mode démo ── */
function _purgeDemoLegacy() {
  if (localStorage.getItem('gw_demo_purged_v1') === '1') return;
  var demoIds = ['dr1', 'dr2', 'dr3', 'dr4'];
  var demoPhone = '+33 6 00 00 00 00';
  try {
    for (var i = 0; i < localStorage.length; i++) {
      var _k = localStorage.key(i);
      if (!_k || _k.indexOf('gw_profile_') !== 0) continue;
      var _email = _k.replace('gw_profile_', '');
      try {
        var _p = JSON.parse(localStorage.getItem(_k)) || {};
        /* Ne touche pas aux profils avec un badge admin-approuvé */
        if (!_p.badgeType) {
          var _changed = false;
          if (_p.identityVerified)              { delete _p.identityVerified;  _changed = true; }
          if (_p.phoneVerified)                 { delete _p.phoneVerified;     _changed = true; }
          if (_p.missionsCompleted)             { delete _p.missionsCompleted; _changed = true; }
          if (_p.rating)                        { delete _p.rating;            _changed = true; }
          if (_p.phone === demoPhone)           { delete _p.phone;             _changed = true; }
          if (_changed) localStorage.setItem(_k, JSON.stringify(_p));
        }
        /* Retire les faux avis démo (IDs dr1..dr4) */
        var _rk = 'gw_reviews_' + _email;
        var _rv = JSON.parse(localStorage.getItem(_rk) || '[]');
        var _cl = _rv.filter(function(r) { return demoIds.indexOf(r.id) === -1; });
        if (_cl.length !== _rv.length) localStorage.setItem(_rk, JSON.stringify(_cl));
      } catch(e2) {}
    }
  } catch(e) {}
  localStorage.setItem('gw_demo_purged_v1', '1');
}
_purgeDemoLegacy();

/* Résout en tâche de fond les URLs de TOUS les Shorts dès la connexion.
   Toutes les requêtes Firebase partent en parallèle → cache localStorage rempli
   → plus aucune attente Firebase lors de l'ouverture du player Shorts. */
function _gwPreloadShortUrls() {
  try {
    var shorts = _vsBuildList();
    shorts.forEach(function(post) {
      var pid = String(post.id);
      if (_gwVidUrlCache[pid] || _gwVidBlobCache[pid]) return;
      /* Vérifie localStorage d'abord (gratuit, synchrone) */
      try {
        var ls = localStorage.getItem('gw_vurl_' + pid);
        if (ls && !ls.startsWith('blob:')) { _gwVidUrlCache[pid] = ls; return; }
        if (ls && ls.startsWith('blob:')) localStorage.removeItem('gw_vurl_' + pid);
      } catch(e2) {}
      /* URL dans le post */
      var pu = typeof post.video === 'string' ? post.video : (post.video && post.video.url ? post.video.url : '');
      if (pu && !pu.startsWith('blob:')) { _gwVidUrlCache[pid] = pu; try { localStorage.setItem('gw_vurl_' + pid, pu); } catch(e3){} return; }
      /* Firebase — requête parallèle pour chaque URL manquante */
      _gwResolveVideoUrl(post, function() {});
    });
  } catch(e) {}
}

function initApp(user) {
  _currentUser = user;
  try { _jobApplyFeatureVisibility(); } catch(e){}
  setTimeout(function() { try { _gwCheckPendingUploads(); } catch(e){} }, 1200);
  /* Pré-résolution des URLs Shorts en arrière-plan, 4 s après login
     (laisse la page se charger complètement avant de consommer du réseau) */
  setTimeout(function() { try { _gwPreloadShortUrls(); } catch(e){} }, 2000);

  /* Crée / renouvelle la session sécurisée */
  if (!_gwLoadSession()) {
    _gwCreateSession(user);
  }

  /* ── Nettoyage listeners Firebase de la session précédente (évite doublons) ── */
  try {
    if (_gwFbDB) {
      if (_gwFbDB._prevInboxRef) _gwFbDB._prevInboxRef.off();
      if (_gwFbDB._prevGrpInboxRef) _gwFbDB._prevGrpInboxRef.off();
      _gwFbDB.ref('gw/dms').off('child_added');
      _gwFbDB.ref('gw/dms').off('child_changed');
      _gwFbDB.ref('gw/profiles').off('child_added');
      _gwFbDB.ref('gw/profiles').off('child_changed');
      _gwFbDB.ref('gw/group_msgs').off('child_added');
      _gwFbDB.ref('gw/group_msgs').off('child_changed');
    }
  } catch(e){}

  /* ── Firebase : écoute les notifs en temps réel pour cet utilisateur ── */
  _gwFbWatchUserNotifs(user.email);
  /* ── Firebase : écoute l'index abonnés en temps réel ── */
  _gwFbWatchFollowers(user.email);
  /* ── Firebase : écoute le compteur d'abonnés du compte officiel ── */
  _gwWatchOfficialFollowers();
  /* ── Présence en ligne (visible par l'admin en temps réel) ── */
  _gwSetOnlinePresence(user);

  /* ── Firebase : sync DMs, inbox et profils en temps réel ── */
  if (_gwFbReady && _gwFbDB && user.email) {
    var _myFbKey = _gwFbKey(user.email);

    /* Suivi toast par expéditeur — évite les doublons et les problèmes de décalage d'horloge */
    var _inboxFirstLoad = true;
    var _dmToastedMap = {};  /* senderFbKey → dernier at toasté */

    function _showInboxToast(entry) {
      if (!entry || !entry.fromEmail || !_currentUser) return;
      var _sk = _gwFbKey(entry.fromEmail);
      if (entry.at && _dmToastedMap[_sk] && entry.at <= _dmToastedMap[_sk]) return;
      var _msgPageActive = (function() {
        var pg = document.getElementById('p-messages');
        var sc = document.getElementById('chat-screen');
        return pg && pg.classList.contains('active') && sc && sc.classList.contains('open');
      })();
      var _convOpen = _msgPageActive && _chatConvId && DEMO_CONVERSATIONS.find(function(c) {
        return c.id === _chatConvId && !c.isGroup && c.email === entry.fromEmail;
      });
      if (_convOpen) return;
      if (entry.at) _dmToastedMap[_sk] = entry.at;
      var _senderName = entry.fromName || entry.fromEmail || 'Quelqu\'un';
      var _preview    = (entry.lastMsg || '').slice(0, 35);
      showToast('💬 ' + _senderName + (_preview ? ' : ' + _preview : ' vous a écrit'), 'ok');
    }

    /* Inbox */
    var _inboxRef = _gwFbDB.ref('gw/inboxes/' + _myFbKey);
    _gwFbDB._prevInboxRef = _inboxRef;
    console.log('[DM] 👂 Écoute inbox:', 'gw/inboxes/' + _myFbKey);
    _inboxRef.on('value', function(snap) {
      var inbox = snap.val();
      console.log('[DM] 📬 inbox reçu:', inbox ? Object.keys(inbox).length + ' entrée(s)' : 'vide');
      if (!inbox || !_currentUser) return;
      var list = Array.isArray(inbox) ? inbox : Object.values(inbox);
      if (_inboxFirstLoad) {
        /* Premier chargement : pré-marquer tous les messages existants → pas de toast */
        _inboxFirstLoad = false;
        list.forEach(function(e) {
          if (e && e.fromEmail && e.at) _dmToastedMap[_gwFbKey(e.fromEmail)] = e.at;
        });
        try { localStorage.setItem('gw_dm_inbox_' + _currentUser.email, JSON.stringify(list)); } catch(e){}
        try { _checkDMInbox(); } catch(e){}
      } else {
        /* Mise à jour ultérieure : toast pour chaque nouveau message */
        list.forEach(function(e) { try { _showInboxToast(e); } catch(e2){} });
        try { localStorage.setItem('gw_dm_inbox_' + _currentUser.email, JSON.stringify(list)); } catch(e){}
        try { _checkDMInbox(); } catch(e){}
      }
    });

    /* DMs : gw/dm_msgs (per-message, atomique) est l'unique source de vérité désormais.
       Les anciens listeners gw/dms sont supprimés pour éviter les doublons et conflits. */

    /* Profils des autres utilisateurs — child_added charge tous les profils existants au login,
       child_changed met à jour en temps réel quand un profil change */
    function _onProfileSnap(snap) {
      try {
        var pFbKey = snap.key;
        var data   = snap.val();
        if (!data) return;
        var email2 = pFbKey.replace(/__d__/g,'.').replace(/__a__/g,'@');
        var existing2 = loadUserProfile(email2) || {};
        /* Firebase est source de vérité — on prend la photo Firebase si elle existe,
           sinon on garde la photo locale (et on re-pousse vers Firebase pour le propriétaire) */
        var merged2;
        if (data.photo) {
          merged2 = Object.assign({}, existing2, data);
        } else if (existing2.photo) {
          merged2 = Object.assign({}, existing2, data, { photo: existing2.photo });
        } else {
          merged2 = Object.assign({}, existing2, data);
        }
        /* ── Badge : Firebase est toujours autoritaire.
           Si un champ badge a été supprimé côté admin, il doit disparaître ici aussi.
           Object.assign ne supprime pas les clés absentes de `data` — on le fait manuellement. */
        var _badgeKeys = ['badgeType','badgeStatus','badgeApprovedAt','badgeCertifiedBy',
                          'badgeCertifiedAt','badgeRevokedAt','badgeRevokedMotif','badgeRevokedBy'];
        _badgeKeys.forEach(function(k) {
          if (k in data) { merged2[k] = data[k]; }
          else           { delete merged2[k]; }
        });
        try { localStorage.setItem('gw_profile_' + email2, JSON.stringify(merged2)); _invalidateProfileCache(email2); } catch(e2){}
        /* Si c'est l'utilisateur courant → synchronise les limites en temps réel */
        if (_currentUser && email2 === _currentUser.email) {
          try { _updateChatMsgCounter(); } catch(e2){}
          try { _subUpdateSidebarChip(merged2.planType || 'free'); } catch(e2){}
        }
        /* Rafraîchit le feed pour mettre à jour les avatars (debounce 300ms) */
        if (document.getElementById('feed-list')) { try { renderFeed(_getFeedPosts()); } catch(e2){} }
      } catch(e){}
    }
    _gwFbDB.ref('gw/profiles').on('child_added',   _onProfileSnap);
    _gwFbDB.ref('gw/profiles').on('child_changed', _onProfileSnap);

    /* Groupes — inbox : notifie quand on est ajouté à un groupe depuis un autre appareil */
    var _grpInboxRef = _gwFbDB.ref('gw/group_inboxes/' + _myFbKey);
    _gwFbDB._prevGrpInboxRef = _grpInboxRef;
    _grpInboxRef.on('value', function(snap) {
      var grpInbox = snap.val();
      if (!grpInbox || !_currentUser) return;
      var list = Array.isArray(grpInbox) ? grpInbox : Object.values(grpInbox);
      try {
        var _grpKey = 'gw_group_inbox_' + String(_currentUser.email).replace(/[^a-z0-9@._]/gi, '_');
        localStorage.setItem(_grpKey, JSON.stringify(list));
        _checkGroupInbox();
      } catch(e){}
    });

    /* Groupes — messages : sync en temps réel */
    _gwFbDB.ref('gw/group_msgs').on('child_added',   function(snap) { try { _gwMergeGroupMsg(snap); } catch(e){} });
    _gwFbDB.ref('gw/group_msgs').on('child_changed', function(snap) { try { _gwMergeGroupMsg(snap); } catch(e){} });

    /* Charge les posts de tous les utilisateurs depuis Firebase au login */
    _gwFbDB.ref('gw/posts').once('value').then(function(snap) {
      var allPosts = snap.val() || {};
      Object.keys(allPosts).forEach(function(fk) {
        var fps = allPosts[fk];
        if (!Array.isArray(fps)) return;
        var em = fk.replace(/__d__/g,'.').replace(/__a__/g,'@');
        try { localStorage.setItem(_userPostsKey(em), JSON.stringify(fps)); } catch(e){}
        fps.forEach(function(p) {
          if (!p || !p.id) return;
          if (!p.images) p.images = [];
          if (!DEMO_POSTS.find(function(d){ return d.id === p.id; })) {
            p.likers = loadPostLikers(p.id);
            DEMO_POSTS.push(p);
          }
        });
      });
      DEMO_POSTS.sort(function(a,b){ return b.id - a.id; });
      _persistedPostsLoaded = true;
      try { if (document.getElementById('feed-list')) renderFeed(_getFeedPosts()); } catch(e){}
    }).catch(function(){});
  }

  /* Initiales de l'avatar */
  var initials = getInitials(user.nom);

  var els = ['composer-initials','pub-initials','sb-initials','comment-initials'];
  els.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = initials;
  });

  /* Nom / email dans la sidebar */
  var sbName  = document.getElementById('sb-name');
  var sbEmail = document.getElementById('sb-email');
  var pubName = document.getElementById('pub-name');
  if (sbName)  sbName.textContent  = user.nom;
  if (sbEmail) sbEmail.textContent = user.email;
  if (pubName) pubName.textContent = user.nom;

  /* Charge les notifications personnelles */
  renderNotifs();

  /* Charge les posts persistés des utilisateurs inscrits */
  _loadAllPersistedPosts();

  /* Charge les likes persistés pour tous les posts */
  getAllPosts().forEach(function(post) {
    post.likers = loadPostLikers(post.id);
  });

  /* Rend les posts du feed — _buildMergedFeedPool intègre les posts officiels automatiquement */
  var _initAllPosts = getAllPosts();
  _feedLastPostCount = _initAllPosts.length;
  renderFeed(_getFeedPosts());

  /* Démarre l'auto-refresh du feed toutes les 30s */
  _feedStartAutoRefresh();

  /* Active le pull-to-refresh sur le feed */
  _initPullToRefresh();

  /* Affiche le bouton éditeur dans la sidebar si autorisé */
  _offUpdateSidebarBtn();

  /* Initialise le profil si c'est la première connexion (sans signal de changement) */
  try {
    var _initProfile = loadUserProfile(_currentUser.email);
    if (!_initProfile) {
      _initProfile = getDefaultProfile(_currentUser);
      try { localStorage.setItem('gw_profile_' + _currentUser.email, JSON.stringify(_initProfile)); _invalidateProfileCache(_currentUser.email); } catch(e) {}
    }
    _subUpdateSidebarChip(_initProfile.planType || 'free');
  } catch(e) {}

  /* Vérifie le renouvellement / expiration / rappel 14j */
  setTimeout(function() {
    try { _subCheckRenewalAndExpiry(); } catch(e) {}
  }, 1500);

  /* Rend la page profil (pré-chargement des données) */
  renderProfilePage();

  /* Met à jour les avatars du compte courant (photo si définie) */
  _refreshCurrentUserAvatars();

  /* Restaure le mode sombre */
  if (localStorage.getItem('gw_dark_mode') === '1') {
    document.body.classList.add('dark-mode');
    var dmToggle = document.getElementById('dark-mode-toggle');
    if (dmToggle) dmToggle.checked = true;
  }

  /* Applique la langue sauvegardée */
  applyLang();

  /* Restaure les conversations DM dynamiques sauvegardées (survit au refresh) */
  try { _loadDMConvList(); } catch(e) {}

  /* Vérifie l'inbox DM au démarrage pour restaurer les convs reçues hors connexion */
  setTimeout(function() {
    try { _checkDMInbox(); } catch(e) {}
    /* Premier poll immédiat pour synchro des messages */
    try { _globalMsgPoll(); } catch(e) {}
  }, 800);

  /* Ré-upload rétroactif des vidéos sans URL Storage (posts anciens ou upload interrompu) */
  setTimeout(function() {
    try { _gwUploadPendingVideos(); } catch(e) {}
    try { _gwUploadPendingOfficialVideos(); } catch(e2) {}
  }, 6000);

  /* Initialise les notifications push (service worker + permission + token FCM).
     Dans l'app Android installée, seul le chemin natif fonctionne de façon fiable
     (la WebView ne délivre pas de vraies notifications système via service worker
     web) — on évite donc d'enregistrer un token web qui écraserait le token natif
     valide au même endroit dans Firebase. */
  setTimeout(function() {
    var isNativeApp = window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform();
    if (isNativeApp) {
      try { _gwInitNativePush(); } catch(e2) {}
    } else {
      try { _gwInitNotifications(); } catch(e) {}
    }
  }, 2000);

  /* Appliquer les sections activées/désactivées par l'admin dès le chargement */
  setTimeout(function() {
    try { _gwApplyMkSections(); } catch(e) {}
    /* Charger l'email PayPal depuis la config admin */
    try {
      var _cfg = _admGetPlansConfig();
      if (_cfg.paypalEmail) _GW_PAYPAL_EMAIL = _cfg.paypalEmail;
    } catch(e) {}
  }, 300);
}

function getInitials(nom) {
  var parts = nom.trim().split(/\s+/);
  if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
  return nom.slice(0, 2).toUpperCase();
}

/* ── Avatar HTML : photo si dispo, sinon initiales ── */
function getAvatarHtml(email, nom, extraClass) {
  var cls = 'user-av' + (extraClass ? ' ' + extraClass : '');
  var dataAttr = email ? ' data-email="' + escHtml(email) + '"' : '';
  var profile = email ? loadUserProfile(email) : null;
  /* Nom live depuis profil */
  var liveName = (profile && profile.nom) ? profile.nom : (nom || '?');
  if (profile && profile.photo) {
    return '<div class="' + cls + ' av-photo"' + dataAttr + '>' +
             '<img src="' + escHtml(profile.photo) + '" alt=""/>' +
           '</div>';
  }
  return '<div class="' + cls + '"' + dataAttr + '><span>' +
           escHtml(getInitials(liveName)) +
         '</span></div>';
}

/* ── Nom affiché toujours à jour depuis le profil ── */
function getDisplayName(email, fallback) {
  if (!email) return fallback || '?';
  var p = loadUserProfile(email);
  return (p && p.nom) ? p.nom : (fallback || '?');
}

/* ── Domaine/rôle toujours à jour depuis le profil ── */
function getDisplayRole(email, fallback) {
  if (!email) return fallback || '';
  var p = loadUserProfile(email);
  return (p && p.domain) ? p.domain : (fallback || '');
}

/* ── Synchronise _currentUser et gw_users avec le profil modifié ── */
function _syncUserRecord(email, newNom) {
  /* Met à jour la session en cours */
  if (_currentUser && _currentUser.email === email) {
    _currentUser.nom = newNom;
    var sbN = document.getElementById('sb-name');  if (sbN) sbN.textContent = newNom;
    var pnN = document.getElementById('pub-name'); if (pnN) pnN.textContent = newNom;
  }
  /* Persiste dans gw_users */
  var users = getUsers();
  var u = users.find(function(x) { return x.email.toLowerCase() === email.toLowerCase(); });
  if (u) { u.nom = newNom; saveUsers(users); }
  /* Rafraîchit le feed (noms des posts), les notifs et les initiales */
  if (document.getElementById('feed-list')) renderFeed(_getFeedPosts());
  _refreshCurrentUserAvatars();
}

/* ── Rafraîchit les avatars du compte courant partout ── */
function _refreshCurrentUserAvatars() {
  if (!_currentUser) return;
  var profile = loadUserProfile(_currentUser.email);
  var photo   = profile && profile.photo ? profile.photo : null;
  var initials = getInitials(_currentUser.nom);

  /* Liste des conteneurs avatar courant */
  var containers = ['composer-av', 'pub-av', 'comment-av', 'sb-av'];
  containers.forEach(function(id) {
    var el = document.getElementById(id);
    if (!el) return;
    if (photo) {
      el.className = el.className.replace(/\bav-photo\b/g, '').trim() + ' av-photo';
      el.innerHTML = '<img src="' + escHtml(photo) + '" alt=""/>';
    } else {
      el.className = el.className.replace(/\bav-photo\b/g, '').trim();
      el.innerHTML = '<span>' + escHtml(initials) + '</span>';
    }
  });

  /* Prénom dans la section héro — mis à jour automatiquement à chaque changement de profil */
  var heroFirst = document.getElementById('hero-firstname');
  if (heroFirst) {
    var firstName = (_currentUser.nom || '').split(' ')[0] || 'Bienvenue';
    heroFirst.textContent = firstName;
  }

  /* Rafraîchit aussi le drawer sidebar */
  _refreshSidebar();

  /* Si la page notifications est active, rafraîchit les avatars en temps réel */
  var notifsPage = document.getElementById('p-notifs');
  if (notifsPage && notifsPage.classList.contains('active')) {
    renderNotifs();
  }
}

/* ── Appelé après que la photo du user courant a été sauvegardée ── */
function _onProfileSaved() {
  renderProfilePage();
  _refreshCurrentUserAvatars(); /* inclut déjà _refreshSidebar() */
  if (document.getElementById('feed-list')) { try { renderFeed(_getFeedPosts()); } catch(e) {} }
  /* Rafraîchir les cartes Marketplace avec la nouvelle photo/nom/badge */
  try { renderMarketplaceUserServices(); } catch(e) {}
  try { _mkRenderSystemListings(); } catch(e) {}
}

/* ── Refresh global déclenché par changement de profil (n'importe quel user) ──
   Appelé depuis _globalMsgPoll quand gw_profile_changed est détecté          ── */
var _lastProfileChangeAt = 0;
function _checkProfileChanges() {
  try {
    var sig = JSON.parse(localStorage.getItem('gw_profile_changed') || 'null');
    if (!sig || sig.at <= _lastProfileChangeAt) return;
    _lastProfileChangeAt = sig.at;
    var changedEmail = sig.email;

    /* Met à jour les images <img> qui affichent ce profil dans toute la page */
    _refreshProfileInDOM(changedEmail);

    /* Re-rend la page active si elle contient des données de cet utilisateur */
    var activePage = document.querySelector('.app-page.active');
    var pageId = activePage ? activePage.id : '';

    if (pageId === 'p-home') {
      try { renderFeed(_getFeedPosts()); } catch(e) {}
    } else if (pageId === 'p-messages') {
      try { renderConversations(); } catch(e) {}
      /* Si chat de groupe ouvert, re-render les messages */
      if (_chatConvId) {
        var openConv = DEMO_CONVERSATIONS.find(function(c) { return c.id === _chatConvId; });
        if (openConv && openConv.isGroup) {
          try { _renderChatMessages(openConv); } catch(e) {}
        }
      }
    } else if (pageId === 'p-notifs') {
      try { renderNotifs(); } catch(e) {}
    } else if (pageId === 'p-marketplace') {
      try { renderMarketplaceUserServices(); } catch(e) {}
    } else if (pageId === 'p-profil') {
      /* Re-render les avatars des collaborateurs / membres visibles */
      try { _collabRender(); } catch(e) {}
    }

    /* Si c'est notre propre profil qui a changé */
    if (_currentUser && changedEmail === _currentUser.email) {
      var p = loadUserProfile(changedEmail);
      if (p && p.nom && p.nom !== _currentUser.nom) _currentUser.nom = p.nom;
      _refreshCurrentUserAvatars(); /* inclut _refreshSidebar() */
      try { renderProfilePage(); } catch(e2) {}
    }
  } catch(e) {}
}

/* Parcourt le DOM et met à jour tous les éléments visuels liés à cet email */
function _refreshProfileInDOM(email) {
  if (!email) return;
  var profile = loadUserProfile(email);
  if (!profile) return;
  var photo = profile.photo || null;
  var nom   = profile.nom   || email;
  var safeEmail = email.replace(/"/g, '');

  /* Avatars `.user-av[data-email]` (getAvatarHtml) */
  document.querySelectorAll('.user-av[data-email="' + safeEmail + '"]').forEach(function(el) {
    if (photo) {
      el.className = (el.className || '').replace(/\bav-photo\b/g, '').trim() + ' av-photo';
      el.innerHTML = '<img src="' + escHtml(photo) + '" alt=""/>';
    } else {
      el.className = (el.className || '').replace(/\bav-photo\b/g, '').trim();
      el.innerHTML = '<span>' + escHtml(getInitials(nom)) + '</span>';
    }
  });

  /* Avatars conv DM `.conv-av-img[data-email]` */
  document.querySelectorAll('[data-email="' + safeEmail + '"]').forEach(function(el) {
    if (el.tagName === 'IMG' && photo) el.src = photo;
  });

  /* Noms `.user-name[data-email]` */
  document.querySelectorAll('.user-name[data-email="' + safeEmail + '"]').forEach(function(el) {
    el.textContent = nom;
  });

  /* Photo dans l'en-tête du chat ouvert si c'est ce contact */
  var chatAvWrap = document.getElementById('chat-contact-av');
  if (chatAvWrap && _chatConvId) {
    var openConv = DEMO_CONVERSATIONS.find(function(c) { return c.id === _chatConvId; });
    if (openConv && !openConv.isGroup && openConv.email === email) {
      chatAvWrap.innerHTML = _convAvatar(openConv, 38);
      var nameEl = document.getElementById('chat-contact-name');
      if (nameEl) nameEl.innerHTML = escHtml(nom);
    }
  }
}

/* ══════════════════════════════════════════
   NAVIGATION INTERNE (pages de l'app)
══════════════════════════════════════════ */

/* Change de page dans l'application + met à jour la bottom nav */
/* ── Auto-refresh du feed ── */
var _feedRefreshTimer  = null;
var _feedLastPostCount = 0;
var _feedCurrentPage   = 'p-home';

function _feedStartAutoRefresh() {
  _feedStopAutoRefresh();
  _feedRefreshTimer = setInterval(function() {
    if (_feedCurrentPage !== 'p-home') return;
    var feedList = document.getElementById('feed-list');
    if (!feedList) return;
    var allPosts  = getAllPosts();
    var newCount  = allPosts.length;
    if (newCount > _feedLastPostCount) {
      /* Nouveaux posts détectés → badge discret en haut du feed */
      _feedShowNewBadge(newCount - _feedLastPostCount);
    }
  }, 30000); /* toutes les 30 secondes */
}

function _feedStopAutoRefresh() {
  if (_feedRefreshTimer) { clearInterval(_feedRefreshTimer); _feedRefreshTimer = null; }
}

function _feedShowNewBadge(count) {
  var existing = document.getElementById('feed-new-badge');
  if (existing) existing.remove();
  var badge = document.createElement('div');
  badge.id = 'feed-new-badge';
  badge.innerHTML = '<i class="fas fa-arrow-up" style="margin-right:5px"></i>' + count + ' nouveau' + (count > 1 ? 'x' : '') + ' post' + (count > 1 ? 's' : '');
  badge.style.cssText = 'position:fixed;top:68px;left:50%;transform:translateX(-50%);' +
    'background:linear-gradient(135deg,#6366F1,#8B5CF6);color:#fff;' +
    'padding:8px 18px;border-radius:20px;font-size:13px;font-weight:700;' +
    'cursor:pointer;z-index:500;box-shadow:0 4px 16px rgba(99,102,241,.35);' +
    'animation:feedBadgePop .3s cubic-bezier(.22,1,.36,1);white-space:nowrap';
  badge.onclick = function() {
    _feedDoRefresh();
    badge.remove();
  };
  document.body.appendChild(badge);
  /* Auto-disparaît après 8s */
  setTimeout(function(){ if (badge.parentNode) badge.remove(); }, 8000);
}

function _feedDoRefresh() {
  /* Scroll to top */
  var feedScroll = document.getElementById('feed-scroll');
  if (feedScroll) feedScroll.scrollTo({ top: 0, behavior: 'smooth' });
  /* Re-render */
  var allPosts = getAllPosts();
  _feedLastPostCount = allPosts.length;
  renderFeed(_getFeedPosts());
  /* Supprimer badge si présent */
  var badge = document.getElementById('feed-new-badge');
  if (badge) badge.remove();
}

function navTo(btn, pageId) {
  var previousPage = _feedCurrentPage;
  _feedCurrentPage = pageId;

  /* Si on retape Accueil alors qu'on y est déjà → refresh immédiat */
  if (pageId === 'p-home' && previousPage === 'p-home') {
    _feedDoRefresh();
    return;
  }

  /* Ferme le chat si on quitte messages → _chatConvId ne reste pas actif */
  if (previousPage === 'p-messages' && pageId !== 'p-messages' && _chatConvId) {
    try { closeChat(); } catch(e) {}
  }

  /* Masque toutes les pages */
  document.querySelectorAll('.app-page').forEach(function(p) {
    p.classList.remove('active');
  });
  document.getElementById(pageId).classList.add('active');

  /* Met à jour la bottom nav */
  document.querySelectorAll('.bnav-item').forEach(function(b) {
    b.classList.remove('active');
  });
  if (btn) btn.classList.add('active');

  /* Sync desktop sidebar nav active state */
  document.querySelectorAll('[data-sdb-page]').forEach(function(b) {
    b.classList.toggle('active', b.getAttribute('data-sdb-page') === pageId);
  });

  /* Refresh feed au retour sur Accueil.
     Si le feed est déjà rendu et que le nombre de posts n'a pas changé,
     on fait juste un scroll-to-top sans rebuild DOM (navigation instantanée). */
  if (pageId === 'p-home') {
    var _allNow = getAllPosts();
    var _feedList = document.getElementById('feed-list');
    var _hasRendered = _feedList && _feedList.children.length > 1; /* >1 = le loader + au moins une carte */
    if (_hasRendered && _allNow.length === _feedLastPostCount) {
      /* Pas de nouveaux posts → scroll to top uniquement */
      var _fs = document.getElementById('feed-scroll');
      if (_fs) _fs.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      _feedDoRefresh();
    }
    try { _gwApplyMkSections(); } catch(e) {}
  }

  if (pageId === 'p-marketplace') {
    /* Rendu immédiat avec ce qui est déjà en cache (localStorage) */
    try { renderMarketplaceUserServices(); } catch(e) {}
    try { _updateMkNotifBadge(); }          catch(e) {}
    try { _updateCartBadge(); }             catch(e) {}
    try { _collabRender(); }                catch(e) {}
    try { _mkRenderTxTabs(); }              catch(e) {}
    try { _gwApplyMkSections(); }           catch(e) {}
    /* Sync Firebase en arrière-plan → re-rendu automatique sans bouton */
    if (_gwFbReady && _gwFbDB) {
      Promise.all([
        _gwFbDB.ref('gw/mk_listings').once('value'),
        _gwFbDB.ref('gw/collab_requests').once('value'),
        _gwFbDB.ref('gw/mk_txns').once('value')
      ]).then(function(snaps) {
        var lstVal    = snaps[0].val();
        var collabVal = snaps[1].val();
        var txVal     = snaps[2].val();
        if (lstVal    !== null) try { localStorage.setItem('gw_mk_listings',      JSON.stringify(Array.isArray(lstVal)    ? lstVal    : Object.values(lstVal)));    } catch(e){}
        if (collabVal !== null) try { localStorage.setItem('gw_collab_requests',  JSON.stringify(Array.isArray(collabVal) ? collabVal : Object.values(collabVal))); } catch(e){}
        if (txVal     !== null) try { localStorage.setItem('gw_mk_txns',          JSON.stringify(Array.isArray(txVal)     ? txVal     : Object.values(txVal)));     } catch(e){}
        try { renderMarketplaceUserServices(); } catch(e) {}
        try { _mkRenderSystemListings(); }       catch(e) {}
        try { _collabRender(); }                 catch(e) {}
        try { _mkRenderTxTabs(); }               catch(e) {}
      }).catch(function(){});
    }
  }

  if (pageId === 'p-jobs') {
    try { _jobRenderList(); } catch(e) {}
    if (_gwFbReady && _gwFbDB) {
      _gwFbDB.ref('gw/jobs').once('value').then(function(snap) {
        var jobsVal = snap.val();
        if (jobsVal !== null) try { localStorage.setItem('gw_jobs', JSON.stringify(Array.isArray(jobsVal) ? jobsVal : Object.values(jobsVal))); } catch(e){}
        try { _jobRenderList(); } catch(e) {}
      }).catch(function(){});
    }
  }

  /* Recalcule les temps relatifs à l'ouverture de la page notifications */
  if (pageId === 'p-notifs') {
    try { renderNotifs(); } catch(e) {}
  }

  /* Sync immédiat des messages non lus à l'ouverture de la page Messages */
  if (pageId === 'p-messages') {
    _globalMsgPoll();
    renderConversations();
  }
}

/* Affiche une page interne sans changer la bottom nav (ex: notifications) */
function showPage(pageId) {
  document.querySelectorAll('.app-page').forEach(function(p) {
    p.classList.remove('active');
  });
  document.getElementById(pageId).classList.add('active');
}

/* Bouton + central → page publier */
function navToPublish() {
  showPage('p-publish');
}

/* ══════════════════════════════════════════
   SIDEBAR DRAWER
══════════════════════════════════════════ */
function openSidebar() {
  document.getElementById('app-sidebar').classList.add('open');
  document.getElementById('sidebar-overlay').classList.add('open');
  _refreshSidebar();
}

function closeSidebar() {
  document.getElementById('app-sidebar').classList.remove('open');
  document.getElementById('sidebar-overlay').classList.remove('open');
}

function toggleSidebar() {
  var sb = document.getElementById('app-sidebar');
  if (sb.classList.contains('open')) {
    closeSidebar();
  } else {
    openSidebar();
  }
}

function _refreshSidebar() {
  if (!_currentUser) return;
  var profile = loadUserProfile(_currentUser.email);
  var nom = profile && profile.nom ? profile.nom : _currentUser.nom;
  var role = profile && profile.domain ? profile.domain : '';

  /* Nom */
  var nameEl = document.getElementById('sidebar-name');
  if (nameEl) nameEl.textContent = nom;

  /* Badge dans la sidebar */
  var sdbBadge = document.getElementById('sidebar-verified');
  if (sdbBadge) {
    var bHtml = getBadgeHtml(_currentUser.email);
    if (bHtml) {
      sdbBadge.innerHTML = bHtml;
      sdbBadge.style.display = 'flex';
    } else {
      sdbBadge.style.display = 'none';
    }
  }

  /* Rôle */
  var roleEl = document.getElementById('sidebar-role');
  if (roleEl) roleEl.textContent = role || 'Membre Geniwork';

  /* Badge vérifié (si compte Google ou badge manuel) */
  var badgeEl = document.getElementById('sidebar-verified');
  if (badgeEl) {
    badgeEl.style.display = (profile && profile.verified) ? 'flex' : 'none';
  }

  /* Avatar */
  var avEl = document.getElementById('sidebar-av');
  if (avEl) {
    if (profile && profile.photo) {
      avEl.innerHTML = '<img src="' + escHtml(profile.photo) + '" alt=""/>';
    } else {
      avEl.innerHTML = '<span>' + escHtml(getInitials(nom)) + '</span>';
    }
  }

  /* Tableau de bord recruteur — visible uniquement si entreprise vérifiée */
  var recBtn = document.getElementById('sdb-recruiter-dash');
  if (recBtn && typeof _jobGetMyVerif === 'function') {
    var myVerif = _jobGetMyVerif(_currentUser.email);
    var isRecruiter = !!(myVerif && myVerif.status === 'approved');
    recBtn.style.display = isRecruiter ? '' : 'none';
    if (isRecruiter) {
      var recBadge = document.getElementById('sdb-recruiter-badge');
      if (recBadge) {
        var nbApps = _jobGetApplicationsForRecruiter(_currentUser.email).filter(function(a) { return a.mode !== 'external' && !a.archived; }).length;
        recBadge.textContent = nbApps;
        recBadge.classList.toggle('hidden', nbApps === 0);
      }
    }
  }
}

function toggleDarkMode(enabled) {
  if (enabled) {
    document.body.classList.add('dark-mode');
    localStorage.setItem('gw_dark_mode', '1');
  } else {
    document.body.classList.remove('dark-mode');
    localStorage.setItem('gw_dark_mode', '0');
  }
}

function openFavorisPage() {
  /* Ouvre le feed filtré sur les favoris */
  var homeBtn = document.querySelector('.bnav-item[data-page="p-home"]');
  navTo(homeBtn, 'p-home');
  /* Filtre l'affichage sur les posts favoris */
  var favs = getFavorites();
  if (!favs.length) {
    showToast('Aucun favori pour l\'instant', '');
    return;
  }
  var favIds = favs.map(function(f) { return f.postId; });
  var filtered = _getFeedPosts().filter(function(p) { return favIds.indexOf(p.id) !== -1; });
  renderFeed(filtered);
  showToast('Affichage de vos ' + filtered.length + ' favori(s)', 'ok');
}

/* ══════════════════════════════════════════
   SYSTÈME DE BADGES
══════════════════════════════════════════ */

/* Clés localStorage */
// profile.badgeType    : null | 'verified' | 'premium' | 'certified'
// profile.badgeStatus  : null | 'pending' | 'approved' | 'rejected'
// profile.identityVerified : bool
// profile.phoneVerified    : bool
// profile.missionsCompleted: number

/* ── Calcul de la complétion du profil (max 7 points) ── */
function getProfileCompletion(email) {
  var p = loadUserProfile(email);
  if (!p) return 0;
  var score = 0;
  if (p.nom)                                            score++;
  if (p.photo)                                          score++;
  if (p.bio && p.bio.trim().length > 10)                score++;
  if (p.domain && p.domain.trim().length > 1)           score++;
  if (p.location && p.location.trim().length > 1)       score++;
  if (p.skills && p.skills.length >= 1)                 score++;
  if (p.phone && p.phone.trim().length >= 8)            score++;
  return score; /* max 7 */
}

/* ── Badge HTML à insérer en ligne à côté d'un nom ── */
function getBadgeHtml(email) {
  if (!email) return '';
  var p = loadUserProfile(email);
  if (!p) return '';
  if (p.badgeType === 'premium') {
    return '<span class="badge-inline badge-inline-gold" title="Badge Premium"><i class="fas fa-crown"></i></span>';
  }
  if (p.badgeType === 'verified') {
    return '<span class="badge-inline badge-inline-blue" title="Profil vérifié"><i class="fas fa-circle-check"></i></span>';
  }
  if (p.badgeType === 'certified') {
    return '<span class="badge-inline badge-inline-green" title="Compte certifié Geniwork"><i class="fas fa-circle-check"></i></span>';
  }
  return '';
}

/* ── Vérifie toutes les conditions pour le badge standard ── */
function checkVerifiedConditions(email) {
  var p = loadUserProfile(email) || {};
  var user = getUsers().find(function(u) { return u.email === email; }) || {};
  var reviews = loadReviews(email);
  var pending = p.badgeStatus === 'pending';

  /* Note moyenne */
  var avgRating = reviews.length
    ? reviews.reduce(function(s, r) { return s + (r.rating || 0); }, 0) / reviews.length
    : 0;

  var missions = p.missionsCompleted || 0;

  /* Les 7 conditions que l'utilisateur contrôle lui-même */
  var userConditions = [
    {
      key:   'profile',
      label: 'Profil complété à 100 %',
      hint:  'Photo, bio, domaine, ville, compétences, téléphone',
      met:   getProfileCompletion(email) >= 7
    },
    {
      key:   'email',
      label: 'Email vérifié',
      hint:  'L\'email de votre compte doit être validé',
      met:   !!(user.verified || user.loginMethod === 'google')
    },
    {
      key:   'phone',
      label: 'Téléphone vérifié',
      hint:  'Ajoutez et vérifiez votre numéro de téléphone',
      met:   !!(p.phone && p.phoneVerified)
    },
    {
      key:   'missions',
      label: 'Minimum 5 missions terminées',
      hint:  missions + ' / 5 missions complétées',
      met:   missions >= 5
    },
    {
      key:   'rating',
      label: 'Note moyenne ≥ 4,5 / 5',
      hint:  reviews.length ? 'Note actuelle : ' + avgRating.toFixed(1) + ' / 5' : 'Aucun avis reçu',
      met:   avgRating >= 4.5
    },
    {
      key:   'reviews',
      label: 'Au moins 3 avis clients',
      hint:  reviews.length + ' avis reçu(s)',
      met:   reviews.length >= 3
    },
    {
      key:   'disputes',
      label: 'Aucun litige grave ou fraude',
      hint:  'Votre compte ne doit pas avoir de signalement',
      met:   !p.hasDispute
    }
  ];

  /* Condition identité — vérifiée par l'admin après soumission du document */
  var identityHint = p.identityVerified
    ? 'Identité confirmée par l\'équipe Geniwork'
    : pending
      ? 'Document soumis — en cours de vérification (48-72h)'
      : 'Envoyez votre CNI ou passeport via le bouton ci-dessous';

  var identityCond = {
    key:        'identity',
    label:      'Identité vérifiée (CNI / passeport)',
    hint:       identityHint,
    met:        !!p.identityVerified,
    isPending:  pending && !p.identityVerified,
    isUpload:   !p.identityVerified && !pending,
    isIdentity: true
  };

  /* Identité affichée en premier */
  var conditions = [identityCond].concat(userConditions);

  var userMet   = userConditions.filter(function(c) { return c.met; }).length;
  var metCount  = conditions.filter(function(c) { return c.met; }).length;
  /* readyToApply = les 7 conditions utilisateur sont toutes remplies */
  var readyToApply = userMet === userConditions.length;

  return {
    conditions:   conditions,
    metCount:     metCount,
    total:        conditions.length,
    userMet:      userMet,
    userTotal:    userConditions.length,
    readyToApply: readyToApply
  };
}

