/* ── Abonnés ── */
function _checkFollowerMilestone(profileEmail, profileKey, count) {
  if (!profileEmail) return;
  _MILE_FOLLOWS.forEach(function(m) {
    if (count < m) return;
    var mkey = 'follows_' + profileKey + '_' + m;
    _mileClaim(mkey, function(claimed) {
      if (!claimed) return;
      var msg = 'Vous avez atteint ' + _mileLabel(m) + ' abonnés !';
      pushNotif(profileEmail, {
        id: genNotifId(), type: 'milestone', fromUser: null,
        postId: null, postPreview: null, msg: '🎉 ' + msg,
        at: Date.now(), time: 'À l\'instant', unread: true
      });
      if (_currentUser && _currentUser.email === profileEmail) _showMilestoneToast('🏆', msg);
    });
  });
}

/* ── Ouvre la vidéo officielle en plein écran au clic ── */
function _openOfficialVideo(postId) {
  var list = _offGetPosts();
  var post = list.find(function(x) { return String(x.id) === String(postId); });
  if (!post || !post.video) return;
  /* Comptage vue */
  _incrementVideoViews('off_' + postId);
  var dur = (typeof post.video === 'object' && post.video.duration) ? post.video.duration : 0;
  var cropPos  = (typeof post.video === 'object' && post.video.cropPos)  ? post.video.cropPos  : null;
  var cropZoom = (typeof post.video === 'object' && post.video.cropZoom) ? post.video.cropZoom : null;
  var trimStart = (typeof post.video === 'object' && post.video.trimStart) ? post.video.trimStart : 0;
  var trimEnd   = (typeof post.video === 'object' && post.video.trimEnd)   ? post.video.trimEnd   : null;
  var muted     = (typeof post.video === 'object') ? !!post.video.muted : false;
  var textLayers = (typeof post.video === 'object') ? post.video.textLayers : null;
  var fx = (typeof post.video === 'object') ? post.video : null;
  /* URL déjà en mémoire ? */
  var url = typeof post.video === 'string' ? post.video : (post.video.url || '');
  if (url) { openVideoPlayer(url, dur, cropPos, cropZoom, trimStart, trimEnd, muted, textLayers, fx); return; }

  /* Fallback Firebase : récupère l'URL Storage depuis gw/post_videos/{postId} */
  function _tryStorageFallback() {
    if (_gwFbReady && _gwFbDB) {
      showToast('Chargement vidéo…', '');
      _gwFbDB.ref('gw/post_videos/' + postId).once('value').then(function(snap) {
        var d = snap.val();
        if (d && d.url) {
          /* Cache l'URL en mémoire et dans localStorage */
          if (typeof post.video === 'object') post.video.url = d.url;
          var all = _offGetPosts();
          var p2 = all.find(function(x) { return String(x.id) === String(postId); });
          if (p2 && p2.video && typeof p2.video === 'object') {
            p2.video.url = d.url;
            try { localStorage.setItem('gw_official_posts', JSON.stringify(all)); } catch(e2){}
          }
          openVideoPlayer(d.url, dur, cropPos, cropZoom, trimStart, trimEnd, muted, textLayers, fx);
        } else {
          showToast('Vidéo introuvable', 'err');
        }
      }).catch(function() {
        showToast('Vidéo introuvable', 'err');
      });
    } else {
      showToast('Vidéo introuvable', 'err');
    }
  }

  /* Résoudre via cache commun (IndexedDB → Firebase) */
  _gwResolveVideoUrl(post, function(url) {
    if (url) { openVideoPlayer(url, dur, cropPos, cropZoom, trimStart, trimEnd, muted, textLayers, fx); }
    else { _tryStorageFallback(); }
  });
}

function _openVideoFromPost(postId, duration) {
  var post = DEMO_POSTS.find(function(p) { return String(p.id) === String(postId); });
  if (!post || !post.video) return;

  var vType = (post.video && post.video.videoType) || 'video';

  if (vType === 'short') {
    /* Short → scroll player TikTok */
    openVideoScroll(postId);
  } else {
    /* Vidéo classique → player YouTube plein écran */
    _openVideoClassic(post, duration);
  }
}

/* Ouvre le player YouTube-style pour une vidéo normale */
function _openVideoClassic(post, duration) {
  var postId = String(post.id);

  /* Vue + milestone */
  var _newViews = _incrementVideoViews(postId);
  _checkViewMilestone(postId, post.ownerEmail || null, _newViews);

  /* Ouvre le player UI immédiatement — ne pas attendre l'URL */
  _vpPopulateDetail(post);
  var modal = document.getElementById('video-player-modal');
  var video  = document.getElementById('vp-video');
  if (modal) modal.style.display = 'flex';
  if (video) video.poster = (post.video && post.video.poster) || '';

  /* Si URL déjà résolue → lecture directe */
  if (_gwVidUrlCache[postId] || post.video.url) {
    var readyUrl = _gwVidUrlCache[postId] || post.video.url;
    openVideoPlayer(readyUrl, duration, post.video.cropPos, post.video.cropZoom, post.video.trimStart, post.video.trimEnd, post.video.muted, post.video.textLayers, post.video);
    _vpPopulateDetail(post);
    return;
  }

  /* Sinon résoudre en arrière-plan (IndexedDB → Firebase) */
  if (video) {
    video.removeAttribute('src');
    /* Spinner visuel pendant la résolution */
    var vpIco = document.getElementById('vp-play-ico');
    if (vpIco) vpIco.className = 'fas fa-spinner fa-spin';
  }
  _gwResolveVideoUrl(post, function(url) {
    if (!url) { showToast('Vidéo non disponible sur cet appareil', 'err'); return; }
    openVideoPlayer(url, duration, post.video.cropPos, post.video.cropZoom, post.video.trimStart, post.video.trimEnd, post.video.muted, post.video.textLayers, post.video);
    _vpPopulateDetail(post);
  });
}

/* ── Helper: build a single comment item HTML ── */
function _vpBuildCommentHtml(c) {
  var cEmail = c.authorEmail || c.email || '';
  var cPr    = (cEmail && loadUserProfile(cEmail)) || {};
  var cNom   = c.authorName || c.author || cPr.nom || (cEmail ? cEmail.split('@')[0] : 'Utilisateur');
  var cBadge = getBadgeHtml(cEmail);
  var cAva   = cPr.photo
    ? '<img class="vpd-comment-avatar" src="' + escHtml(cPr.photo) + '" onerror="this.style.display=\'none\'" />'
    : '<div class="vpd-comment-avatar-initials">' + escHtml(cNom.charAt(0).toUpperCase()) + '</div>';
  return '<div class="vpd-comment-item">' +
    cAva +
    '<div class="vpd-comment-body">' +
      '<div class="vpd-comment-author">' + escHtml(cNom) + ' ' + cBadge +
        '<span class="vpd-comment-time">· ' + (c.timeDisplay || _timeAgo(c.at || 0)) + '</span>' +
      '</div>' +
      '<div class="vpd-comment-text" id="vpdctxt-' + c.id + '" data-full="' + escHtml(c.text || '') + '" data-tags="' + escHtml(JSON.stringify(c.tags || [])) + '">' +
        _gwRenderTaggedText((c.text || '').length > 120 ? (c.text || '').slice(0, 120) : (c.text || ''), c.tags) +
        ((c.text || '').length > 120
          ? '… <span class="see-more" style="cursor:pointer;color:#2563EB;font-weight:600" onclick="event.stopPropagation();_vpdExpandComment(\'' + c.id + '\')">Voir plus</span>'
          : '') +
      '</div>' +
    '</div>' +
  '</div>';
}

/* Expand le texte complet d'un commentaire tronqué (vue détaillée vidéo) */
function _vpdExpandComment(commentId) {
  var el = document.getElementById('vpdctxt-' + commentId);
  if (!el) return;
  var full = el.getAttribute('data-full') || '';
  var tags = [];
  try { tags = JSON.parse(el.getAttribute('data-tags') || '[]'); } catch(e) {}
  el.innerHTML = _gwRenderTaggedText(full, tags);
}

/* ── Populates YouTube-style detail sections (title/author/desc/comments/related) ── */
var _vpCurrentPost = null;

/* Reconstruit le bloc commentaires (compteur + aperçu défilant) — appelée à
   l'ouverture de la vidéo ET chaque fois qu'un commentaire est ajouté, pour
   que le compteur et le défilement ne restent jamais figés à l'état initial */
function _vpRefreshCommentsPreview(post) {
  if (_vpCommentsTimer) { clearInterval(_vpCommentsTimer); _vpCommentsTimer = null; }
  var commWrap = document.getElementById('vpd-comments-wrap');
  if (!commWrap) return;
  var cList  = getAllComments(post.id).slice().reverse();
  var cCount = cList.length;
  var previewHtml = cCount > 0
    ? '<div id="vpd-comment-preview" class="vpd-comment-preview">' + _vpBuildCommentHtml(cList[0]) + '</div>'
    : '<div class="vpd-no-comments">Soyez le premier à commenter ✨</div>';
  commWrap.innerHTML =
    '<div class="vpd-comments-hdr">' +
      '<span class="vpd-comments-title">Commentaires (' + cCount + ')</span>' +
      '<button class="vpd-voir-tout-btn" onclick="openComments(' + post.id + ')">Voir tout</button>' +
    '</div>' +
    previewHtml +
    '<div class="vpd-add-comment" onclick="openComments(' + post.id + ')">' +
      '<div class="vpd-add-comment-placeholder"><i class="fas fa-pen-to-square"></i> Ajouter un commentaire...</div>' +
    '</div>';
  /* Lance le défilement si plusieurs commentaires */
  if (cList.length > 1) {
    var _cIdx = 0;
    _vpCommentsTimer = setInterval(function() {
      _cIdx = (_cIdx + 1) % cList.length;
      var el = document.getElementById('vpd-comment-preview');
      if (!el) { clearInterval(_vpCommentsTimer); _vpCommentsTimer = null; return; }
      el.style.opacity = '0';
      setTimeout(function() {
        if (el) { el.innerHTML = _vpBuildCommentHtml(cList[_cIdx]); el.style.opacity = '1'; }
      }, 300);
    }, 3500);
  }
}

function _vpPopulateDetail(post) {
  _vpCurrentPost = post;

  /* Title — prefer video.title (set at publish), fall back to post text */
  var _vidTitle = (post.video && post.video.title) || post.text || post.content || 'Vidéo';
  var titleEl   = document.getElementById('vpd-title');
  if (titleEl) titleEl.textContent = _vidTitle;

  /* Stats: views + time */
  var statsEl = document.getElementById('vpd-stats');
  if (statsEl) statsEl.textContent = _fmtViews(_getVideoViews(post.id)) + ' vues · ' + _timeAgo(post.at || post.id);

  /* Like / dislike counts — always read fresh from localStorage */
  post.likers = loadPostLikers(post.id);
  var lCnt     = document.getElementById('vpd-like-cnt');
  var dCnt     = document.getElementById('vpd-dislike-cnt');
  var sCnt     = document.getElementById('vpd-share-cnt');
  var dislikers = loadPostDislikers(post.id);
  if (lCnt) lCnt.textContent = _fmtViews((post.baseLikes || 0) + post.likers.length);
  if (dCnt) dCnt.textContent = _fmtViews(dislikers.length) || '0';
  if (sCnt) sCnt.textContent = _fmtViews(_getShareCount(post.id));

  /* Like / dislike / save active state */
  var email = _currentUser ? _currentUser.email : '';
  var liked    = email && post.likers && post.likers.indexOf(email) !== -1;
  var disliked = email && dislikers.indexOf(email) !== -1;
  var saved    = isFavorite(post.id);
  var likeBtn  = document.getElementById('vpd-like-btn');
  var disBtn   = document.getElementById('vpd-dislike-btn');
  var saveIco  = document.getElementById('vpd-save-ico');
  var bmIco    = document.getElementById('vpd-bm-ico');
  var saveActBtn = document.getElementById('vpd-save-act-btn');
  if (likeBtn)    likeBtn.classList.toggle('active', liked);
  if (disBtn)     disBtn.classList.toggle('active',  disliked);
  if (saveIco)    saveIco.className = saved ? 'fas fa-bookmark' : 'far fa-bookmark';
  if (bmIco)      bmIco.className   = saved ? 'fas fa-bookmark' : 'far fa-bookmark';
  if (saveActBtn) saveActBtn.classList.toggle('active', saved);

  /* Author */
  var pr       = (post.ownerEmail && loadUserProfile(post.ownerEmail)) || {};
  var nom      = pr.nom  || (post.ownerEmail ? post.ownerEmail.split('@')[0] : 'Utilisateur');
  var photo    = pr.photo || '';
  var ownerKey = post.ownerEmail ? _gwFbKey(post.ownerEmail) : '';
  var profKey  = post.ownerEmail ? getProfileKey({ nom: nom, email: post.ownerEmail }) : '';
  var following = profKey ? isFollowing(profKey) : false;
  var subs      = profKey ? _getTotalFollowers(profKey, false) : 0;
  var badge     = getBadgeHtml(post.ownerEmail);
  var isOwn     = email && post.ownerEmail === email;

  var suivreBtn = document.getElementById('vpd-suivre-btn');
  if (suivreBtn) {
    suivreBtn.textContent = following ? 'Suivi' : 'Suivre';
    suivreBtn.classList.toggle('following', following);
    suivreBtn.style.display = isOwn ? 'none' : '';
  }

  var authorRow = document.getElementById('vpd-author-row');
  if (authorRow) {
    var avatarHtml = photo
      ? '<img class="vpd-author-avatar" src="' + escHtml(photo) + '" alt="" onerror="this.style.display=\'none\'" />'
      : '<div class="vpd-author-initials">' + escHtml(nom.charAt(0).toUpperCase()) + '</div>';
    var _vpProfCall = 'openUserProfile({nom:\'' + escHtml(nom).replace(/'/g,"\\'") + '\',email:\'' + escHtml(post.ownerEmail || '').replace(/'/g,"\\'") + '\'})';
    authorRow.innerHTML =
      '<div class="vpd-author-clickable" onclick="' + _vpProfCall + '">' +
        avatarHtml +
        '<div class="vpd-author-info">' +
          '<div class="vpd-author-name">' + escHtml(nom) + ' ' + badge + '</div>' +
          '<div class="vpd-author-subs">' + _fmtViews(subs) + ' abonné' + (subs > 1 ? 's' : '') + '</div>' +
        '</div>' +
      '</div>' +
      (isOwn ? '' :
        '<button class="vpd-subscribe-btn' + (following ? ' following' : '') + '" onclick="vpToggleFollow()">' +
          (following ? 'Abonné' : 'S\'abonner') +
        '</button>');
  }

  /* Description — only show if user set a custom video title; otherwise post.text is
     already displayed as the title and repeating it would create a duplicate */
  var descWrap = document.getElementById('vpd-desc-wrap');
  if (descWrap) {
    var desc        = post.text || post.content || '';
    var hasOwnTitle = post.video && post.video.title && post.video.title.trim().length > 0;
    if (desc && hasOwnTitle) {
      descWrap.innerHTML =
        '<div class="vpd-desc-title">Description</div>' +
        '<div class="vpd-desc-text' + (desc.length > 120 ? '' : ' expanded') + '" id="vpd-desc-text">' + escHtml(desc) + '</div>' +
        (desc.length > 120 ?
          '<button class="vpd-voir-plus" id="vpd-voir-plus" onclick="vpExpandDesc()">Voir plus</button>' : '');
    } else {
      descWrap.innerHTML = '';
    }
  }

  /* Comments — count + cycling preview + add-comment bar */
  _vpRefreshCommentsPreview(post);

  /* Related videos */
  var relEl = document.getElementById('vpd-related');
  if (relEl) {
    var cat   = (post.video && post.video.category) || '';
    var all   = _vdAllVideos();
    var related = all.filter(function(p) { return String(p.id) !== String(post.id); });
    /* Prefer same category, then same author, then any */
    var sameCat    = related.filter(function(p) { return cat && (p.video.category || '') === cat; });
    var sameAuthor = related.filter(function(p) { return p.ownerEmail && p.ownerEmail === post.ownerEmail; });
    var merged = []; var seen = {};
    sameCat.concat(sameAuthor).concat(related).forEach(function(p) {
      if (!seen[p.id]) { seen[p.id] = 1; merged.push(p); }
    });
    var toShow = merged.slice(0, 8);
    if (!toShow.length) {
      relEl.innerHTML = '<div style="padding:16px;color:#64748B;font-size:13px;text-align:center">Aucune autre vidéo disponible</div>';
    } else {
      relEl.innerHTML = toShow.map(function(p) {
        var rpr   = (p.ownerEmail && loadUserProfile(p.ownerEmail)) || {};
        var rnom  = rpr.nom || (p.ownerEmail ? p.ownerEmail.split('@')[0] : 'Utilisateur');
        var rSrc  = (p.video.url && !p.video.url.startsWith('blob:')) ? escHtml(p.video.url) : '';
        var rDur  = formatDuration(p.video.duration || 0);
        var rView = _fmtViews(_getVideoViews(p.id));
        var rBadge = rpr.badge ? '<i class="fas fa-circle-check vd-verified"></i>' : '';
        return '<div class="vd-list-item" onclick="_openVideoFromPost(\'' + p.id + '\',' + (p.video.duration||0) + ')">' +
          '<div class="vd-list-thumb">' +
            (rSrc ? '<video src="' + rSrc + '" preload="metadata" muted playsinline></video>' :
              '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center"><i class="fas fa-video" style="color:#3B82F6;opacity:.4;font-size:18px"></i></div>') +
            '<span class="vd-list-dur">' + rDur + '</span>' +
          '</div>' +
          '<div class="vd-list-info">' +
            '<div class="vd-list-title">' + escHtml((p.text || p.content || 'Vidéo').substring(0, 60)) + '</div>' +
            '<div class="vd-list-author">@' + escHtml(rnom) + ' ' + rBadge + '</div>' +
            '<div class="vd-list-stats">' + rView + ' vues</div>' +
          '</div>' +
          '<button class="vd-list-menu" onclick="event.stopPropagation();vsShowMenu(\'' + p.id + '\',\'' + escHtml(p.ownerEmail || '') + '\')"><i class="fas fa-ellipsis-v"></i></button>' +
        '</div>';
      }).join('');
    }
  }

  /* Scroll to top */
  var sc = document.getElementById('vpd-scroll');
  if (sc) sc.scrollTop = 0;
}

/* ── Video detail action buttons ── */
/* ── Helpers pour rafraîchir les deux boutons ensemble (exclusivité mutuelle) ── */
function _vpRefreshLikeDislike() {
  var post  = _vpCurrentPost;
  var email = _currentUser ? _currentUser.email : '';
  /* Always read fresh state */
  post.likers = loadPostLikers(post.id);
  var liked    = email && post.likers.indexOf(email) !== -1;
  var dislikers = loadPostDislikers(post.id);
  var disliked  = email && dislikers.indexOf(email) !== -1;
  var likeTotal = (post.baseLikes || 0) + post.likers.length;

  var lb   = document.getElementById('vpd-like-btn');
  var db   = document.getElementById('vpd-dislike-btn');
  var lCnt = document.getElementById('vpd-like-cnt');
  var dCnt = document.getElementById('vpd-dislike-cnt');

  /* Exclusivité visuelle garantie : un seul peut être actif */
  if (lb)   lb.classList.toggle('active', !!liked);
  if (db)   db.classList.toggle('active', !!disliked);
  if (lCnt) lCnt.textContent = _fmtViews(likeTotal);
  if (dCnt) dCnt.textContent = _fmtViews(dislikers.length);
}

function vpToggleLike() {
  if (!_vpCurrentPost) return;
  if (!_currentUser) { showToast('Connectez-vous pour liker', 'err'); return; }
  likePost(_vpCurrentPost.id);   /* retire aussi le dislike en interne */
  _vpRefreshLikeDislike();
}

function vpToggleDislike() {
  if (!_vpCurrentPost) return;
  if (!_currentUser) { showToast('Connectez-vous pour réagir', 'err'); return; }
  dislikePost(_vpCurrentPost.id); /* retire aussi le like en interne */
  _vpRefreshLikeDislike();
}

function vpToggleFollow() {
  if (!_vpCurrentPost) return;
  var post = _vpCurrentPost;
  var pr   = (post.ownerEmail && loadUserProfile(post.ownerEmail)) || {};
  var nom  = pr.nom || (post.ownerEmail ? post.ownerEmail.split('@')[0] : '');
  _doFollowToggle({ nom: nom, email: post.ownerEmail, role: pr.role || '' });
  /* Update subscribe button in author row */
  var profKey  = post.ownerEmail ? getProfileKey({ nom: nom, email: post.ownerEmail }) : '';
  var following = profKey ? isFollowing(profKey) : false;
  var subBtn = document.querySelector('#vpd-author-row .vpd-subscribe-btn');
  if (subBtn) { subBtn.textContent = following ? 'Abonné' : 'S\'abonner'; subBtn.classList.toggle('following', following); }
}

function vpToggleSave() {
  if (!_vpCurrentPost) return;
  toggleFavorite(_vpCurrentPost.id);
  var saved      = isFavorite(_vpCurrentPost.id);
  var saveIco    = document.getElementById('vpd-save-ico');
  var bmIco      = document.getElementById('vpd-bm-ico');
  var saveActBtn = document.getElementById('vpd-save-act-btn');
  var favCntEl   = document.getElementById('vpd-fav-cnt');
  if (saveIco)    saveIco.className = saved ? 'fas fa-bookmark' : 'far fa-bookmark';
  if (bmIco)      bmIco.className   = saved ? 'fas fa-bookmark' : 'far fa-bookmark';
  if (saveActBtn) saveActBtn.classList.toggle('active', saved);
  if (favCntEl) {
    var fc = _getFavCount(_vpCurrentPost.id);
    favCntEl.textContent = fc > 0 ? _fmtViews(fc) : '';
    favCntEl.style.display = fc > 0 ? '' : 'none';
  }
  _renderFavPosts();
  showToast(saved ? 'Vidéo enregistrée ✓' : 'Vidéo retirée des favoris', saved ? 'ok' : '');
}

function vpShare() {
  if (!_vpCurrentPost) return;
  sharePost(_vpCurrentPost.id);
}

function vpMoreMenu() {
  if (!_vpCurrentPost) return;
  vsShowMenu(_vpCurrentPost.id, _vpCurrentPost.ownerEmail || '');
}

function vpExpandDesc() {
  var txt = document.getElementById('vpd-desc-text');
  var btn = document.getElementById('vpd-voir-plus');
  if (txt) txt.classList.add('expanded');
  if (btn) btn.remove();
}

/* ── Comments cycle timer ── */
var _vpCommentsTimer = null;

/* ── Auto-next (proposer la vidéo suivante à la fin) ── */
var _vpAutoNextTimer    = null;
var _vpAutoNextPost     = null;
var _vpAutoNextInterval = null;

function _vpGetNextPost() {
  if (!_vpCurrentPost) return null;
  var all = _vdAllVideos();
  var idx = all.findIndex(function(p) { return String(p.id) === String(_vpCurrentPost.id); });
  /* Cherche dans les related d'abord */
  var cat = (_vpCurrentPost.video && _vpCurrentPost.video.category) || '';
  var candidates = all.filter(function(p) { return String(p.id) !== String(_vpCurrentPost.id); });
  var sameCat    = candidates.filter(function(p) { return cat && (p.video.category || '') === cat; });
  var pool = sameCat.length ? sameCat : candidates;
  return pool.length ? pool[0] : null;
}

function _vpStartAutoNext() {
  var next = _vpGetNextPost();
  _vpAutoNextPost = next;
  var panel = document.getElementById('vpd-autonext');
  if (!panel || !next) return;

  /* Miniature de la prochaine vidéo */
  var thumb = document.getElementById('vpd-autonext-thumb');
  if (thumb) {
    var vSrc = (next.video.url && !next.video.url.startsWith('blob:')) ? next.video.url : '';
    thumb.innerHTML = vSrc
      ? '<video src="' + escHtml(vSrc) + '" preload="metadata" muted playsinline style="width:100%;height:100%;object-fit:cover;display:block"></video>'
      : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:#1E293B"><i class="fas fa-video" style="color:#3B82F6;font-size:28px;opacity:.5"></i></div>';
  }

  panel.style.display = 'flex';
  var cdEl = document.getElementById('vpd-autonext-cd');
  var remaining = 5;
  if (cdEl) cdEl.textContent = remaining;

  _vpAutoNextInterval = setInterval(function() {
    remaining--;
    if (cdEl) cdEl.textContent = remaining;
    if (remaining <= 0) {
      _vpCancelAutoNextTimer();
      vpPlayNext();
    }
  }, 1000);
}

function _vpCancelAutoNextTimer() {
  clearInterval(_vpAutoNextInterval);
  _vpAutoNextInterval = null;
}

function vpPlayNext() {
  _vpCancelAutoNextTimer();
  var panel = document.getElementById('vpd-autonext');
  if (panel) panel.style.display = 'none';
  if (_vpAutoNextPost) {
    _openVideoFromPost(String(_vpAutoNextPost.id), _vpAutoNextPost.video.duration || 0);
  }
}

/* ── Boutons gauche/droite : sauter à la vidéo précédente/suivante ── */
function _vpGetSiblingPost(direction) {
  if (!_vpCurrentPost) return null;
  var all = _vdAllVideos();
  var idx = all.findIndex(function(p) { return String(p.id) === String(_vpCurrentPost.id); });
  if (idx === -1) return null;
  var newIdx = idx + direction;
  if (newIdx < 0) newIdx = all.length - 1;   /* boucle en fin de liste */
  if (newIdx >= all.length) newIdx = 0;      /* boucle au début */
  return all[newIdx] || null;
}

function vpGoPrevVideo() {
  var p = _vpGetSiblingPost(-1);
  if (!p) { showToast('Aucune autre vidéo', ''); return; }
  _openVideoFromPost(String(p.id), p.video.duration || 0);
}

function vpGoNextVideo() {
  var p = _vpGetSiblingPost(1);
  if (!p) { showToast('Aucune autre vidéo', ''); return; }
  _openVideoFromPost(String(p.id), p.video.duration || 0);
}

function vpCancelAutoNext() {
  _vpCancelAutoNextTimer();
  var panel = document.getElementById('vpd-autonext');
  if (panel) panel.style.display = 'none';
  _vpAutoNextPost = null;
}

/* ── Signaler un post ── */
/* Retourne tous les emails admin (super admin + admins membres) */
function _gwGetAdminEmails() {
  var emails = [];
  var sa = (function(){ try { return JSON.parse(localStorage.getItem('gw_sadmin')); } catch(e){ return null; } })();
  if (sa && sa.email) emails.push(sa.email);
  var admins = (function(){ try { return JSON.parse(localStorage.getItem('gw_admins') || '[]'); } catch(e){ return []; } })();
  admins.forEach(function(a) { if (a.email && emails.indexOf(a.email) === -1) emails.push(a.email); });
  return emails;
}

function reportPost(postId) {
  _closeGenericSheet('report-post');
  var bg = document.createElement('div');
  bg.className = 'cam-sheet-bg'; bg.id = 'report-post-bg';
  bg.onclick = function() { _closeGenericSheet('report-post'); };

  var card = document.createElement('div');
  card.className = 'cam-sheet-card'; card.id = 'report-post-card';

  var reasons = ['Contenu inapproprié', 'Spam ou publicité', 'Harcèlement ou intimidation', 'Fausses informations', 'Autre raison'];
  var items = reasons.map(function(r) {
    return '<button class="post-menu-item" onclick="_sendReport(' + postId + ',\'' + r.replace(/'/g,"\\'") + '\')">' +
      '<span class="pmi-ico" style="background:#FFF7ED;color:#EA580C"><i class="fas fa-flag"></i></span>' +
      '<span class="pmi-label">' + escHtml(r) + '</span>' +
    '</button>';
  }).join('');

  card.innerHTML =
    '<div class="cam-sheet-handle"></div>' +
    '<p class="cam-sheet-title">Pourquoi signalez-vous ce contenu ?</p>' +
    '<div class="post-menu-list">' + items + '</div>' +
    '<div style="padding:8px 16px 24px">' +
      '<button class="btn-outline full" onclick="_closeGenericSheet(\'report-post\')">Annuler</button>' +
    '</div>';

  document.body.appendChild(bg);
  document.body.appendChild(card);
}

function _sendReport(postId, reason) {
  _closeGenericSheet('report-post');
  if (!_currentUser) return;

  /* Retrouve le post pour enrichir le signalement */
  var post = getAllPosts().find(function(p) { return String(p.id) === String(postId); });
  var targetEmail   = post ? (post.ownerEmail || '') : '';
  var targetDisplay = post ? (post.ownerEmail || post.author || '?') : String(postId);

  /* Détermine le type exact de contenu */
  var postType = 'texte';
  if (post && post.video) {
    postType = (post.video.videoType === 'short') ? 'short' : 'video';
  } else if (post && post.images && post.images.length) {
    postType = 'image';
  }

  /* Prévisualisation du contenu signalé */
  var preview = '';
  if (post) {
    if (post.video && post.video.title) preview = post.video.title;
    else if (post.text) preview = post.text.slice(0, 80);
    else if (post.video) preview = '[' + postType + ']';
  }

  var report = {
    id:           'rpt_' + Date.now(),
    date:         new Date().toISOString(),
    postId:       String(postId),
    target:       targetDisplay,
    targetEmail:  targetEmail,
    reason:       reason,
    type:         postType,   /* 'texte' | 'image' | 'video' | 'short' */
    preview:      preview,
    reporterEmail: _currentUser.email,
    reporterNom:  _currentUser.nom || _currentUser.email
  };

  try {
    var key  = 'gw_reports_' + _currentUser.email;
    var reps = JSON.parse(localStorage.getItem(key) || '[]');
    reps.unshift(report); /* plus récent en premier */
    localStorage.setItem(key, JSON.stringify(reps));
    _gwFbSet('reports/' + _gwFbKey(_currentUser.email), reps);
  } catch(e) {}

  /* Notifie tous les admins en temps réel */
  _gwGetAdminEmails().forEach(function(adminEmail) {
    pushNotif(adminEmail, {
      id:       'adm_rpt_' + Date.now(),
      type:     'bug_report',
      at:       Date.now(),
      title:    '🚩 Nouveau signalement',
      body:     postType.toUpperCase() + ' signalé par ' + (_currentUser.nom || _currentUser.email) + ' : ' + reason,
      msg:      '🚩 Signalement ' + postType + ' : "' + preview.slice(0,50) + '" — Raison : ' + reason,
      fromUser: { nom: _currentUser.nom, email: _currentUser.email },
      unread:   true
    });
  });

  showToast('Signalement envoyé. Merci !', 'ok');
}

/* ── Masquer un post ── */
function hidePost(postId) {
  var key     = 'gw_hidden_posts';
  var hidden  = JSON.parse(localStorage.getItem(key) || '[]');
  if (hidden.indexOf(postId) === -1) hidden.push(postId);
  localStorage.setItem(key, JSON.stringify(hidden));

  var card = document.getElementById('post-' + postId);
  if (card) card.remove();
  showToast('Publication masquée', 'ok');
}

/* ── Bloquer un utilisateur ── */
function blockUser(postId) {
  var post = getAllPosts().find(function(p) { return p.id === postId; });
  if (!post) return;

  var blockedEmail = post.ownerEmail;
  var blockedName  = post.author;

  if (!confirm('Bloquer ' + blockedName + ' ?\n\nSes publications ne seront plus visibles.')) return;

  var key     = 'gw_blocked_' + (_currentUser ? _currentUser.email : '');
  var blocked = JSON.parse(localStorage.getItem(key) || '[]');
  if (blocked.indexOf(blockedEmail || blockedName) === -1) {
    blocked.push(blockedEmail || blockedName);
  }
  localStorage.setItem(key, JSON.stringify(blocked));
  if (_gwFbReady && _gwFbDB && _currentUser) {
    _gwFbDB.ref('gw/blocked/' + _gwFbKey(_currentUser.email)).set(blocked).catch(function(){});
  }

  /* Retire toutes les publications de cet utilisateur du feed */
  document.querySelectorAll('.post-card').forEach(function(card) {
    var id = parseInt(card.id.replace('post-', ''), 10);
    var p  = getAllPosts().find(function(x) { return x.id === id; });
    if (p && (p.ownerEmail === blockedEmail || p.author === blockedName)) card.remove();
  });

  showToast(escHtml(blockedName) + ' a été bloqué', 'ok');
}

/* ══════════════════════════════════════════
   COMMENTAIRES — STOCKAGE PERSISTANT
══════════════════════════════════════════ */

var _likersCache = {};
function loadPostLikers(postId) {
  var k = String(postId);
  if (_likersCache[k] !== undefined) return _likersCache[k]; /* [] (0 likes) est falsy — vérifier undefined */
  var v = JSON.parse(localStorage.getItem('gw_likers_' + k) || '[]');
  _likersCache[k] = v;
  return v;
}
function savePostLikers(postId, likers) {
  _likersCache[String(postId)] = likers;
  localStorage.setItem('gw_likers_' + postId, JSON.stringify(likers));
}
/* Écrit un like per-child — atomique, pas de race condition */
function _fbLikeWrite(postId, email, liked) {
  if (!_gwFbReady || !_gwFbDB) return;
  var ref = _gwFbDB.ref('gw/likes/' + postId + '/' + _gwFbKey(email));
  if (liked) { ref.set(email).catch(function(){}); }
  else        { ref.remove().catch(function(){}); }
}

function loadUserComments(postId) {
  return JSON.parse(localStorage.getItem('gw_comments_' + postId) || '[]');
}
function saveUserComments(postId, comments) {
  localStorage.setItem('gw_comments_' + postId, JSON.stringify(comments));
  /* Pas de .set(fullArray) — les writes individuels se font dans submitComment/deleteComment */
}

/* Récupère réactions d'un commentaire (👍/👎) */
function getCommentReact(cid) {
  return JSON.parse(localStorage.getItem('gw_creact_' + cid) || '{"likes":[],"dislikes":[]}');
}
function saveCommentReact(cid, react) {
  localStorage.setItem('gw_creact_' + cid, JSON.stringify(react));
  if (_gwFbReady && _gwFbDB && cid) {
    _gwFbDB.ref('gw/creact/' + cid).set(react).catch(function(){});
  }
}

/* Tous les commentaires d'un post = demo (fixes) + utilisateurs (localStorage) */
function getAllComments(postId) {
  /* ── Publications officielles (post, vidéo ou short) — stockage séparé (_offGetPosts) ── */
  var offPost = _offGetPosts().find(function(p) { return String(p.id) === String(postId); });
  if (offPost) {
    return (Array.isArray(offPost.comments) ? offPost.comments : []).map(function(c) {
      return {
        id:          c.id,
        postId:      offPost.id,
        parentId:    null,
        authorEmail: c.email || '',
        authorName:  c.nom || 'Membre',
        text:        c.text,
        tags:        c.tags || [],
        at:          c.at || 0,
        timeDisplay: c.time || 'Récent',
        readOnly:    true
      };
    });
  }

  var post = getAllPosts().find(function(p) { return p.id === postId; });
  var demo = (post && Array.isArray(post.comments)) ? post.comments.map(function(c, i) {
    return {
      id: 'demo_' + postId + '_' + i,
      postId: postId,
      parentId: null,
      authorEmail: 'demo@geniwork.com',
      authorName: c.author,
      text: c.text,
      timeDisplay: 'Récent',
      isDemo: true
    };
  }) : [];
  return demo.concat(loadUserComments(postId));
}

/* ── OUVRIR / FERMER ── */
function openComments(postId) {
  _currentPostId = postId;
  cancelReply();
  document.getElementById('comment-input').value = '';
  document.getElementById('comments-overlay').classList.remove('hidden');
  document.getElementById('comments-panel').classList.remove('hidden');
  renderCommentsList(postId);
  setTimeout(function() {
    document.getElementById('comment-input').focus();
  }, 350);
}

function closeComments() {
  document.getElementById('comments-overlay').classList.add('hidden');
  document.getElementById('comments-panel').classList.add('hidden');
  _currentPostId = null;
  cancelReply();
}

/* ── RENDU DE LA LISTE ── */
function renderCommentsList(postId) {
  var list = document.getElementById('comments-list');
  list.innerHTML = '';

  var all      = getAllComments(postId);
  var topLevel = all.filter(function(c) { return !c.parentId; });

  /* Compteur dans l'en-tête */
  var countEl = document.getElementById('comments-count');
  if (countEl) countEl.textContent = all.length > 0 ? '(' + all.length + ')' : '';

  if (topLevel.length === 0) {
    list.innerHTML = '<p style="text-align:center;color:#9CA3AF;padding:30px 0;font-size:13px">' +
      'Aucun commentaire. Soyez le premier !</p>';
    return;
  }

  topLevel.forEach(function(c) {
    list.appendChild(buildCommentEl(c, false));
    /* Réponses imbriquées */
    all.filter(function(r) { return r.parentId === c.id; })
      .forEach(function(r) { list.appendChild(buildCommentEl(r, true)); });
  });

  list.scrollTop = list.scrollHeight;
}

function buildCommentEl(c, isReply) {
  /* Commentaires officiels : lecture seule dans cette modale unifiée (pas d'édition/
     suppression/réaction ici — l'id de post officiel est une chaîne 'off_…', pas un
     nombre, donc pas compatible avec editComment/likeComment qui attendent un id de
     publication classique). */
  if (c.readOnly) {
    var displayCommentNameRO = getDisplayName(c.authorEmail || null, c.authorName);
    var elRO = document.createElement('div');
    elRO.className = 'comment-item' + (isReply ? ' comment-reply' : '');
    elRO.id = 'comment-' + c.id;
    elRO.innerHTML =
      getAvatarHtml(c.authorEmail || null, displayCommentNameRO, 'sm') +
      '<div class="comment-content">' +
        '<div class="comment-bubble">' +
          '<div class="comment-header">' +
            '<span class="comment-author">' + escHtml(displayCommentNameRO) + '</span>' +
            '<span class="comment-time">' + escHtml(c.at ? _timeAgo(c.at) : (c.timeDisplay || '')) + '</span>' +
          '</div>' +
          '<div class="comment-text" id="ctxt-' + c.id + '">' + _gwRenderTaggedText(c.text || '', c.tags) + '</div>' +
        '</div>' +
      '</div>';
    return elRO;
  }

  var isOwn   = _currentUser && c.authorEmail === _currentUser.email && !c.isDemo;
  var react   = getCommentReact(c.id);
  var email   = _currentUser ? _currentUser.email : '';
  var liked   = react.likes.indexOf(email) !== -1;
  var disliked= react.dislikes.indexOf(email) !== -1;

  var el = document.createElement('div');
  el.className = 'comment-item' + (isReply ? ' comment-reply' : '');
  el.id = 'comment-' + c.id;

  var ownBtns = isOwn
    ? '<div class="comment-own-actions">' +
        '<button onclick="editComment(\'' + c.id + '\',' + c.postId + ')" title="Modifier">' +
          '<i class="fas fa-pen"></i>' +
        '</button>' +
        '<button onclick="deleteComment(\'' + c.id + '\',' + c.postId + ')" title="Supprimer">' +
          '<i class="fas fa-trash"></i>' +
        '</button>' +
      '</div>'
    : '';

  var replyBtn = !isReply
    ? '<button class="c-act-btn c-reply-btn" onclick="openReply(\'' + c.id + '\')">' +
        '<i class="fas fa-reply"></i> Répondre' +
      '</button>'
    : '';

  var displayCommentName = getDisplayName(c.authorEmail || null, c.authorName);
  el.innerHTML =
    getAvatarHtml(c.authorEmail || null, displayCommentName, 'sm') +
    '<div class="comment-content">' +
      '<div class="comment-bubble">' +
        '<div class="comment-header">' +
          '<span class="comment-author">' + escHtml(displayCommentName) + '</span>' +
          '<span class="comment-time">' + escHtml(c.at ? _timeAgo(c.at) : (c.timeDisplay || '')) + '</span>' +
          (c.edited ? '<span class="edited-label">(modifié)</span>' : '') +
          ownBtns +
        '</div>' +
        '<div class="comment-text" id="ctxt-' + c.id + '" data-full="' + escHtml(c.text || '') + '" data-tags="' + escHtml(JSON.stringify(c.tags || [])) + '">' +
          _gwRenderTaggedText((c.text || '').length > 200 ? (c.text || '').slice(0, 200) : (c.text || ''), c.tags) +
          ((c.text || '').length > 200
            ? '… <span class="rp-voir-plus" style="color:#2563EB;cursor:pointer;font-weight:600" onclick="expandComment(\'' + c.id + '\')">Voir plus</span>'
            : '') +
        '</div>' +
      '</div>' +
      '<div class="comment-actions">' +
        replyBtn +
        '<button id="clike-btn-' + c.id + '" class="c-act-btn' + (liked ? ' c-liked' : '') + '" ' +
          'onclick="likeComment(\'' + c.id + '\',' + c.postId + ',false)">' +
          '<i class="fas fa-thumbs-up"></i>' +
          '<span id="clikes-' + c.id + '">' + (react.likes.length || '') + '</span>' +
        '</button>' +
        '<button id="cdislike-btn-' + c.id + '" class="c-act-btn' + (disliked ? ' c-disliked' : '') + '" ' +
          'onclick="likeComment(\'' + c.id + '\',' + c.postId + ',true)">' +
          '<i class="fas fa-thumbs-down"></i>' +
          '<span id="cdislikes-' + c.id + '">' + (react.dislikes.length || '') + '</span>' +
        '</button>' +
      '</div>' +
    '</div>';

  return el;
}

/* ── SOUMETTRE UN COMMENTAIRE / RÉPONSE ── */
/* ══════════════════════════════════════════
   EMOJI PICKER — commentaires
══════════════════════════════════════════ */
var _EMOJI_LIST = [
  '😀','😂','🤣','😊','😍','🥰','😘','😎','🤩','😏',
  '😢','😭','😡','🤬','😱','🤯','🥳','🤔','🙄','😴',
  '👍','👎','👏','🙌','🤝','🤜','💪','🙏','👀','🫶',
  '❤️','🧡','💛','💚','💙','💜','🖤','🤍','💔','💯',
  '🔥','⭐','✨','🎉','🎊','🎶','🎵','💡','⚡','🌈',
  '😅','😬','🤭','🥴','🤗','😤','😫','😩','🥺','😋',
  '👋','✌️','🤞','🖖','🤙','💅','🫁','🤦','🤷','🫠',
  '🍕','🍔','🎂','🍦','☕','🍺','🥂','🍾','🌮','🍜'
];

function _toggleEmojiPicker(e) {
  if (e) e.stopPropagation();
  var panel = document.getElementById('emoji-picker-panel');
  if (!panel) return;
  if (panel.classList.contains('hidden')) {
    _openEmojiPicker();
  } else {
    _closeEmojiPicker();
  }
}

function _openEmojiPicker() {
  var panel = document.getElementById('emoji-picker-panel');
  if (!panel) return;
  if (!panel._built) {
    panel.innerHTML = _EMOJI_LIST.map(function(e) {
      return '<button class="emoji-btn" onclick="_insertEmoji(\'' + e + '\')">' + e + '</button>';
    }).join('');
    panel._built = true;
  }
  panel.classList.remove('hidden');
  /* Ferme si clic ailleurs — retire l'ancien listener avant d'en ajouter un nouveau */
  document.removeEventListener('click', _closeEmojiPicker);
  setTimeout(function() {
    document.addEventListener('click', _closeEmojiPicker, { once: true });
  }, 0);
}

function _closeEmojiPicker() {
  var panel = document.getElementById('emoji-picker-panel');
  if (panel) panel.classList.add('hidden');
}

function _insertEmoji(emoji) {
  var inp = document.getElementById('comment-input');
  if (!inp) return;
  var start = inp.selectionStart || inp.value.length;
  var end   = inp.selectionEnd   || inp.value.length;
  inp.value = inp.value.slice(0, start) + emoji + inp.value.slice(end);
  inp.selectionStart = inp.selectionEnd = start + emoji.length;
  inp.focus();
}

/* ══════════════════════════════════════════
   SYSTÈME DE TAG (@mention) — autocomplétion + rendu coloré + notification
══════════════════════════════════════════ */

/* Branche la détection "@" sur un champ texte (composer ou commentaire) */
function _gwAttachMentionSupport(inputEl) {
  if (!inputEl || inputEl._gwMentionAttached) return;
  inputEl._gwMentionAttached = true;
  inputEl.addEventListener('input', function() { _gwMentionOnInput(inputEl); });
  inputEl.addEventListener('blur', function() { setTimeout(_gwCloseMentionDropdown, 150); });
}

function _gwMentionOnInput(el) {
  try {
    var val = el.value || '';
    var pos = el.selectionStart;
    var before = val.slice(0, pos);
    var m = before.match(/@([^\s@]{0,30})$/);
    if (!m) { _gwCloseMentionDropdown(); return; }
    var query = m[1].toLowerCase();
    var users = getUsers().filter(function(u) {
      if (_currentUser && u.email === _currentUser.email) return false;
      var nom = getDisplayName(u.email, u.nom) || '';
      return nom.toLowerCase().indexOf(query) !== -1;
    }).slice(0, 6);
    if (!users.length) { _gwCloseMentionDropdown(); return; }
    _gwShowMentionDropdown(el, users, m[0].length);
  } catch(e) { _gwCloseMentionDropdown(); }
}

function _gwShowMentionDropdown(el, users, matchLen) {
  var dd = document.getElementById('gw-mention-dropdown');
  if (!dd) {
    dd = document.createElement('div');
    dd.id = 'gw-mention-dropdown';
    dd.className = 'gw-mention-dropdown';
    document.body.appendChild(dd);
  }
  var rect = el.getBoundingClientRect();
  /* Hauteur visible réelle (tient compte du clavier virtuel quand l'API existe) */
  var viewportH = (window.visualViewport && window.visualViewport.height) || window.innerHeight;
  var viewportW = (window.visualViewport && window.visualViewport.width)  || window.innerWidth;
  var MARGIN    = 8;
  var TOPBAR_H  = 64; /* évite de passer sous la barre du haut */

  var spaceAbove = rect.top - TOPBAR_H - MARGIN;
  var spaceBelow = viewportH - rect.bottom - MARGIN;

  /* Choisit le côté qui offre le plus de place, avec une hauteur mini utile */
  var openBelow = spaceBelow >= 120 || spaceBelow >= spaceAbove;
  var available = Math.max(120, openBelow ? spaceBelow : spaceAbove);

  dd.style.position  = 'fixed';
  dd.style.maxHeight = Math.min(260, available) + 'px';
  dd.style.left      = Math.max(MARGIN, Math.min(rect.left, viewportW - 280 - MARGIN)) + 'px';
  dd.style.width     = Math.min(Math.max(rect.width, 220), 280) + 'px';
  if (openBelow) {
    dd.style.top       = (rect.bottom + MARGIN) + 'px';
    dd.style.transform = 'none';
  } else {
    dd.style.top       = rect.top + 'px';
    dd.style.transform = 'translateY(-100%) translateY(-' + MARGIN + 'px)';
  }
  dd.style.display   = 'block';
  dd.innerHTML = users.map(function(u) {
    var nom    = getDisplayName(u.email, u.nom);
    var photo  = (loadUserProfile(u.email) || {}).photo || '';
    var avatar = photo
      ? '<img src="' + photo + '" class="gw-mention-av">'
      : '<span class="gw-mention-av-ph">' + escHtml((nom || '?').charAt(0).toUpperCase()) + '</span>';
    var safeEmail = (u.email || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
    var safeNom   = (nom || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
    var safeInputId = el.id;
    return '<div class="gw-mention-item" onmousedown="event.preventDefault();_gwPickMention(\'' + safeInputId + '\',\'' + safeEmail + '\',\'' + safeNom + '\',' + matchLen + ')">' +
      avatar + '<span>' + escHtml(nom) + getBadgeHtml(u.email) + '</span>' +
    '</div>';
  }).join('');
}

function _gwCloseMentionDropdown() {
  var dd = document.getElementById('gw-mention-dropdown');
  if (dd) dd.style.display = 'none';
}

function _gwPickMention(inputId, email, nom, matchLen) {
  var el = document.getElementById(inputId);
  if (!el) return;
  var pos    = el.selectionStart;
  var val    = el.value;
  var before = val.slice(0, pos - matchLen);
  var after  = val.slice(pos);
  var insert = '@' + nom + ' ';
  el.value   = before + insert + after;
  var newPos = (before + insert).length;
  el.focus();
  try { el.setSelectionRange(newPos, newPos); } catch(e) {}
  var tags = _gwGetPendingTags(el);
  if (!tags.some(function(t) { return t.email === email; })) tags.push({ email: email, nom: nom });
  _gwCloseMentionDropdown();
}

function _gwGetPendingTags(el) {
  if (!el) return [];
  if (!el._gwPendingTags) el._gwPendingTags = [];
  return el._gwPendingTags;
}

/* ══════════════════════════════════════════
   SYSTÈME HASHTAGS
══════════════════════════════════════════ */

var _gwHashtagCache = {};

function _gwLoadHashtagCache() {
  if (!_gwFbDB) return;
  _gwFbDB.ref('gw/hashtags').once('value').then(function(snap) {
    _gwHashtagCache = snap.val() || {};
  }).catch(function(){});
}

function _gwExtractHashtags(text) {
  var matches = (text || '').match(/#([a-zA-ZÀ-ɏ0-9_]{1,50})/g) || [];
  return matches.map(function(m) { return m.slice(1).toLowerCase(); })
    .filter(function(t, i, arr) { return arr.indexOf(t) === i; });
}

function _gwSaveHashtags(text) {
  if (!_gwFbDB || !text) return;
  var tags = _gwExtractHashtags(text);
  tags.forEach(function(tag) {
    _gwFbDB.ref('gw/hashtags/' + tag + '/count').transaction(function(cur) {
      return (cur || 0) + 1;
    }).then(function(res) {
      if (res.snapshot) _gwHashtagCache[tag] = { count: res.snapshot.val() };
    }).catch(function(){});
    _gwFbDB.ref('gw/hashtags/' + tag + '/lastUsed').set(Date.now()).catch(function(){});
  });
}

function _gwHashtagSuggest(ta) {
  try {
    var val    = ta.value || '';
    var pos    = ta.selectionStart;
    var before = val.slice(0, pos);
    var m = before.match(/#([a-zA-ZÀ-ɏ0-9_]{0,50})$/);
    var dd = document.getElementById('gw-hashtag-suggest');
    if (!dd) return;
    if (!m) { dd.style.display = 'none'; return; }
    var query = m[1].toLowerCase();
    var suggestions = Object.keys(_gwHashtagCache)
      .filter(function(t) { return query.length === 0 || t.indexOf(query) === 0; })
      .sort(function(a, b) {
        var ca = (_gwHashtagCache[a] && _gwHashtagCache[a].count) || 0;
        var cb = (_gwHashtagCache[b] && _gwHashtagCache[b].count) || 0;
        return cb - ca;
      })
      .slice(0, 6);
    if (!suggestions.length) { dd.style.display = 'none'; return; }
    dd.style.display = 'block';
    dd.innerHTML = suggestions.map(function(tag) {
      var cnt = (_gwHashtagCache[tag] && _gwHashtagCache[tag].count) || 0;
      var safeTag = tag.replace(/'/g, "\\'");
      return '<div style="padding:10px 14px;cursor:pointer;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid #334155" ' +
        'onmousedown="event.preventDefault();_gwPickHashtag(\'' + safeTag + '\',\'pub-text\')">' +
        '<span style="color:#A78BFA;font-weight:700">#' + escHtml(tag) + '</span>' +
        '<span style="font-size:11px;color:#94A3B8">' + cnt + ' utilisation' + (cnt > 1 ? 's' : '') + '</span>' +
        '</div>';
    }).join('');
  } catch(e) {
    var dd2 = document.getElementById('gw-hashtag-suggest');
    if (dd2) dd2.style.display = 'none';
  }
}

function _gwPickHashtag(tag, inputId) {
  var el = document.getElementById(inputId);
  if (!el) return;
  var pos    = el.selectionStart;
  var val    = el.value;
  var before = val.slice(0, pos);
  var after  = val.slice(pos);
  var m = before.match(/#([a-zA-ZÀ-ɏ0-9_]{0,50})$/);
  if (m) before = before.slice(0, before.length - m[0].length);
  el.value = before + '#' + tag + ' ' + after;
  var newPos = (before + '#' + tag + ' ').length;
  el.focus();
  try { el.setSelectionRange(newPos, newPos); } catch(e) {}
  var dd = document.getElementById('gw-hashtag-suggest');
  if (dd) dd.style.display = 'none';
}

function _gwOpenHashtagFeed(tag) {
  var allPosts = getAllPosts().concat(_offGetPosts ? _offGetPosts() : []);
  var filtered = allPosts.filter(function(p) {
    return (p.text || '').toLowerCase().indexOf('#' + tag) !== -1;
  });
  showPage('p-home');
  setTimeout(function() {
    if (!filtered.length) { showToast('Aucune publication avec #' + tag, 'info'); return; }
    renderFeed(filtered);
    showToast('#' + tag + ' — ' + filtered.length + ' publication(s)', 'ok');
  }, 300);
}

/* Ferme le dropdown hashtag si on clique ailleurs */
(function() {
  var _taEl = document.getElementById('pub-text');
  if (_taEl) _taEl.addEventListener('blur', function() {
    setTimeout(function() {
      var dd = document.getElementById('gw-hashtag-suggest');
      if (dd) dd.style.display = 'none';
    }, 150);
  });
})();

/* Rend un texte avec ses tags colorés/cliquables — échappe le texte en amont,
   donc toujours appeler avec le texte BRUT (jamais déjà échappé). */
function _gwRenderTaggedText(text, tags) {
  var escaped = escHtml(text || '');
  if (tags && tags.length) {
    tags.forEach(function(t) {
      if (!t || !t.nom) return;
      var escName = escHtml(t.nom).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      var pattern;
      try { pattern = new RegExp('@' + escName, 'g'); } catch(e) { return; }
      var safeEmail = (t.email || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
      var safeNomJs = (t.nom   || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
      escaped = escaped.replace(pattern,
        '<span class="gw-tag-mention" onclick="event.stopPropagation();openUserProfile({email:\'' + safeEmail + '\',nom:\'' + safeNomJs + '\'})">@' + escHtml(t.nom) + getBadgeHtml(t.email) + '</span>'
      );
    });
  }
  /* Rend les #hashtags en violet/cliquable */
  escaped = escaped.replace(/#([a-zA-ZÀ-ɏ0-9_]{1,50})/g, function(match, tag) {
    var safeTag = tag.toLowerCase().replace(/'/g, "\\'");
    return '<span class="gw-hashtag" onclick="event.stopPropagation();_gwOpenHashtagFeed(\'' + safeTag + '\')" ' +
      'style="color:#8B5CF6;font-weight:600;cursor:pointer">#' + escHtml(tag) + '</span>';
  });
  return escaped;
}

/* Notifie chaque utilisateur taggé (sauf soi-même) — réutilise le routing des
   notifications de commentaire (ouvre la publication + les commentaires) */
function _gwNotifyTags(tags, postId, fromUser) {
  if (!tags || !tags.length || !fromUser) return;
  tags.forEach(function(t) {
    if (!t || !t.email || t.email === fromUser.email) return;
    pushNotif(t.email, {
      id:       genNotifId(),
      type:     'tag',
      title:    '🏷️ Vous avez été taggé(e)',
      body:     (fromUser.nom || 'Quelqu\'un') + ' vous a taggé(e) dans une publication',
      fromUser: { nom: fromUser.nom, email: fromUser.email, role: 'Membre Geniwork' },
      postId:   postId,
      msg:      'vous a taggé(e)',
      at:       Date.now(), time: 'À l\'instant',
      unread:   true
    });
  });
}

/* Active l'autocomplétion @mention sur les deux champs concernés */
try {
  _gwAttachMentionSupport(document.getElementById('pub-text'));
  _gwAttachMentionSupport(document.getElementById('comment-input'));
} catch(e) {}

function submitComment() {
  var input    = document.getElementById('comment-input');
  var text     = input.value.trim();
  var parentId = document.getElementById('reply-parent-id').value || null;
  if (!text || !_currentPostId || !_currentUser) return;

  /* ── Vérification restriction ── */
  if (_gwIsRestricted(_currentUser.email)) {
    if (_gwShowRestrictionAlert('comment')) return;
  }

  /* ── Publication officielle (post, vidéo ou short) — stockage séparé ── */
  var _offPosts = _offGetPosts();
  var _offTarget = _offPosts.find(function(p) { return String(p.id) === String(_currentPostId); });
  if (_offTarget) {
    var _offCmtTags = _gwGetPendingTags(input).slice();
    if (!Array.isArray(_offTarget.comments)) _offTarget.comments = [];
    _offTarget.comments.push({
      id:    'oc_' + Date.now(),
      nom:   _currentUser.nom || 'Membre',
      email: _currentUser.email,
      text:  text,
      tags:  _offCmtTags,
      at:    Date.now(), time: 'À l\'instant'
    });
    _offSavePosts(_offPosts);
    input.value = '';
    input._gwPendingTags = [];
    cancelReply();
    renderCommentsList(_currentPostId);
    updatePostCommentCount(_currentPostId);
    _gwNotifyTags(_offCmtTags, _currentPostId, _currentUser);
    return;
  }

  /* ── Respecte "Autoriser les commentaires" de l'auteur du post ── */
  var _cPost = getAllPosts().find(function(p) { return String(p.id) === String(_currentPostId); });
  if (_cPost && _cPost.ownerEmail && _cPost.ownerEmail !== _currentUser.email) {
    var _cPriv = _privLoadForEmail(_cPost.ownerEmail);
    if (_cPriv.commentsFrom === 'disabled') {
      showToast('Les commentaires sont désactivés sur cette publication', 'err');
      return;
    }
    if (_cPriv.commentsFrom === 'followers' && !isFollowing(_cPost.ownerEmail)) {
      showToast('Seuls les abonnés peuvent commenter cette publication', 'err');
      return;
    }
  }

  /* ── Analyse du contenu ── */
  var _cc = _gwCheckContent(text);
  if (_cc.flagged) {
    showToast('🚫 Commentaire bloqué — ' + _cc.reason, 'err');
    _gwApplyRestriction(_currentUser.email, _currentUser.nom, _cc.type, _cc.reason, 'auto');
    input.value = '';
    return;
  }

  var _cmtTags = _gwGetPendingTags(input).slice();

  var newC = {
    id:          'c_' + genNotifId(),
    postId:      _currentPostId,
    parentId:    parentId,
    authorEmail: _currentUser.email,
    authorName:  _currentUser.nom,
    text:        text,
    tags:        _cmtTags,
    at:          Date.now(),
    edited:      false,
    isDemo:      false
  };

  var comments = loadUserComments(_currentPostId);
  comments.push(newC);
  saveUserComments(_currentPostId, comments);
  if (_gwFbReady && _gwFbDB) {
    _gwFbDB.ref('gw/comments/' + _currentPostId + '/' + newC.id).set(newC).catch(function(){});
  }

  _gwNotifyTags(_cmtTags, _currentPostId, _currentUser);

  input.value = '';
  input._gwPendingTags = [];
  cancelReply();
  renderCommentsList(_currentPostId);
  updatePostCommentCount(_currentPostId);

  /* Milestone commentaires */
  var post = getAllPosts().find(function(p) { return p.id === _currentPostId; });
  if (post) {
    var _totalComments = getAllComments(_currentPostId).length;
    _checkCommentMilestone(_currentPostId, post.ownerEmail || null, _totalComments);
  }

  /* Notification au propriétaire */
  if (!post) post = getAllPosts().find(function(p) { return String(p.id) === String(_currentPostId); });
  if (post && post.ownerEmail && post.ownerEmail !== _currentUser.email) {
    var _cmtType = post.video ? 'votre vidéo' : (post.images && post.images.length ? 'votre photo' : 'votre publication');
    var _cmtMsg  = parentId ? 'a répondu à un commentaire' : ('a commenté ' + _cmtType);
    pushNotif(post.ownerEmail, {
      id:          genNotifId(),
      type:        'comment',
      title:       '💬 Nouveau commentaire',
      body:        _currentUser.nom + ' ' + _cmtMsg,
      fromUser:    { nom: _currentUser.nom, email: _currentUser.email, role: 'Membre Geniwork' },
      postId:      post.id,
      postPreview: '"' + text.slice(0, 55) + (text.length > 55 ? '…' : '') + '"',
      msg:         _cmtMsg,
      at:          Date.now(), time: 'À l\'instant',
      unread:      true
    });
  }
}

/* ── MODIFIER UN COMMENTAIRE ── */
function editComment(cid, postId) {
  var textEl = document.getElementById('ctxt-' + cid);
  if (!textEl) return;
  var current = textEl.textContent;
  textEl.innerHTML =
    '<textarea class="comment-edit-area" id="cedit-' + cid + '">' + escHtml(current) + '</textarea>' +
    '<div class="comment-edit-btns">' +
      '<button class="c-cancel-btn" onclick="cancelEditComment(\'' + cid + '\',\'' +
        current.replace(/'/g, '\\\'') + '\')">Annuler</button>' +
      '<button class="c-save-btn" onclick="saveEditComment(\'' + cid + '\',' + postId + ')">Sauvegarder</button>' +
    '</div>';
  var ta = document.getElementById('cedit-' + cid);
  if (ta) { ta.focus(); ta.setSelectionRange(ta.value.length, ta.value.length); }
}

function cancelEditComment(cid, original) {
  var textEl = document.getElementById('ctxt-' + cid);
  if (textEl) textEl.innerHTML = escHtml(original);
}

function saveEditComment(cid, postId) {
  var ta = document.getElementById('cedit-' + cid);
  if (!ta) return;
  var newText = ta.value.trim();
  if (!newText) return;

  var comments = loadUserComments(postId);
  var c = comments.find(function(x) { return x.id === cid; });
  if (c) { c.text = newText; c.edited = true; saveUserComments(postId, comments); }

  var textEl = document.getElementById('ctxt-' + cid);
  if (textEl) textEl.innerHTML = escHtml(newText);

  /* Ajoute label "modifié" si pas déjà là */
  var header = document.querySelector('#comment-' + cid + ' .comment-header');
  if (header && !header.querySelector('.edited-label')) {
    var lbl = document.createElement('span');
    lbl.className = 'edited-label';
    lbl.textContent = '(modifié)';
    header.insertBefore(lbl, header.querySelector('.comment-own-actions'));
  }
  showToast('Commentaire modifié ✓', 'ok');
}

/* ── SUPPRIMER UN COMMENTAIRE ── */
function deleteComment(cid, postId) {
  var comments = loadUserComments(postId);
  var toDelete = comments.filter(function(x) { return x.id === cid || x.parentId === cid; });
  /* Supprime le commentaire et ses réponses */
  comments = comments.filter(function(x) { return x.id !== cid && x.parentId !== cid; });
  saveUserComments(postId, comments);
  if (_gwFbReady && _gwFbDB) {
    toDelete.forEach(function(x) {
      _gwFbDB.ref('gw/comments/' + postId + '/' + x.id).remove().catch(function(){});
    });
  }

  /* Supprime aussi les éléments DOM (commentaire + réponses) */
  var el = document.getElementById('comment-' + cid);
  if (el) el.remove();
  /* Réponses dont parentId = cid */
  document.querySelectorAll('[id^="comment-"]').forEach(function(node) {
    /* On re-rend proprement */
  });
  renderCommentsList(postId);
  updatePostCommentCount(postId);
  showToast('Commentaire supprimé', 'ok');
}

/* ── LIKE / DISLIKE D'UN COMMENTAIRE ── */
function likeComment(cid, postId, isDislike) {
  if (!_currentUser) { showToast('Connectez-vous pour voter', 'err'); return; }
  var email = _currentUser.email;
  var react = getCommentReact(cid);
  var arr     = isDislike ? react.dislikes : react.likes;
  var opposite= isDislike ? react.likes    : react.dislikes;

  var oppIdx = opposite.indexOf(email);
  if (oppIdx !== -1) opposite.splice(oppIdx, 1);

  var idx = arr.indexOf(email);
  if (idx !== -1) arr.splice(idx, 1);
  else arr.push(email);

  saveCommentReact(cid, react);

  var liked    = react.likes.indexOf(email) !== -1;
  var disliked = react.dislikes.indexOf(email) !== -1;

  var lBtn = document.getElementById('clike-btn-' + cid);
  var dBtn = document.getElementById('cdislike-btn-' + cid);
  var lSpan= document.getElementById('clikes-' + cid);
  var dSpan= document.getElementById('cdislikes-' + cid);

  if (lBtn)  lBtn.className  = 'c-act-btn' + (liked    ? ' c-liked'    : '');
  if (dBtn)  dBtn.className  = 'c-act-btn' + (disliked ? ' c-disliked' : '');
  if (lSpan) lSpan.textContent  = react.likes.length    || '';
  if (dSpan) dSpan.textContent  = react.dislikes.length || '';
}

/* ── RÉPONSES ── */
function openReply(cid) {
  var authorEl = document.querySelector('#comment-' + cid + ' .comment-author');
  var name = authorEl ? authorEl.textContent : 'ce commentaire';
  document.getElementById('reply-parent-id').value = cid;
  document.getElementById('reply-to-name').textContent = name;
  document.getElementById('reply-indicator').classList.remove('hidden');
  document.getElementById('comment-input').placeholder = 'Répondre à ' + name + '…';
  document.getElementById('comment-input').focus();
}

function cancelReply() {
  document.getElementById('reply-parent-id').value = '';
  var ind = document.getElementById('reply-indicator');
  if (ind) ind.classList.add('hidden');
  var inp = document.getElementById('comment-input');
  if (inp) inp.placeholder = 'Écrire un commentaire…';
}

/* ── COMPTEUR SUR LA CARTE ── */
function updatePostCommentCount(postId) {
  var total = getAllComments(postId).length;
  /* Met à jour toutes les instances de ce post (feed + profil) */
  document.querySelectorAll('#ccount-' + postId).forEach(function(span) {
    span.textContent = total > 0 ? total : '';
  });
  /* Met à jour aussi le compteur dans la vue scroll (VS) */
  var vsEl = document.getElementById('vs-coms-' + postId);
  if (vsEl) vsEl.textContent = total > 0 ? _fmtViews(total) : '0';
  var countEl = document.getElementById('comments-count');
  if (countEl && _currentPostId === postId) countEl.textContent = total > 0 ? '(' + total + ')' : '';
  /* Rafraîchit le bloc commentaires de la vue détaillée vidéo (compteur figé sinon) */
  if (_vpCurrentPost && String(_vpCurrentPost.id) === String(postId)) {
    try { _vpRefreshCommentsPreview(_vpCurrentPost); } catch(e) {}
  }
}

/* ══════════════════════════════════════════
   FAVORIS — POSTS
══════════════════════════════════════════ */
function _favsKey() {
  return _currentUser ? 'gw_favorites_' + _currentUser.email : null;
}
function getFavorites() {
  var k = _favsKey(); if (!k) return [];
  return JSON.parse(localStorage.getItem(k) || '[]');
}
function saveFavorites(list) {
  var k = _favsKey(); if (!k) return;
  localStorage.setItem(k, JSON.stringify(list));
}
function isFavorite(postId) {
  return getFavorites().some(function(f) { return f.postId === postId; });
}
/* ── Compteur global de favoris par post ── */
function _getFavCount(postId) {
  return parseInt(localStorage.getItem('gw_fav_count_' + postId) || '0', 10);
}
function _changeFavCount(postId, delta) {
  /* Mise à jour optimiste locale immédiate */
  var nLocal = Math.max(0, _getFavCount(postId) + delta);
  localStorage.setItem('gw_fav_count_' + postId, nLocal);
  document.querySelectorAll('[data-fav-cnt="' + postId + '"]').forEach(function(el) {
    el.textContent = nLocal > 0 ? _fmtViews(nLocal) : '0';
    el.style.display = nLocal > 0 ? '' : 'none';
  });
  /* Sync Firebase via transaction atomique pour éviter les conflits entre appareils */
  if (_gwFbReady && _gwFbDB) {
    _gwFbDB.ref('gw/favcounts/' + postId).transaction(function(current) {
      var cur = typeof current === 'number' ? current : 0;
      return Math.max(0, cur + delta);
    }, function(err, committed, snap) {
      if (!err && committed && snap) {
        var serverVal = snap.val();
        if (typeof serverVal === 'number') {
          localStorage.setItem('gw_fav_count_' + postId, serverVal);
          document.querySelectorAll('[data-fav-cnt="' + postId + '"]').forEach(function(el) {
            el.textContent = serverVal > 0 ? _fmtViews(serverVal) : '0';
            el.style.display = serverVal > 0 ? '' : 'none';
          });
        }
      }
    });
  }
}

function toggleFavorite(postId) {
  if (!_currentUser) { showToast('Connectez-vous pour sauvegarder', 'err'); return; }
  var list = getFavorites();
  var idx  = -1;
  for (var i = 0; i < list.length; i++) { if (list[i].postId === postId) { idx = i; break; } }
  if (idx !== -1) {
    list.splice(idx, 1);
    saveFavorites(list);
    _setFavBtn(postId, false);
    _changeFavCount(postId, -1);
    showToast('Retiré des favoris', '');
  } else {
    list.unshift({ postId: postId, savedAt: Date.now() });
    saveFavorites(list);
    _setFavBtn(postId, true);
    _changeFavCount(postId, +1);
    showToast('🔖 Ajouté aux favoris ✓', 'ok');
  }
}
function _setFavBtn(postId, active) {
  document.querySelectorAll('#fav-btn-' + postId).forEach(function(btn) {
    btn.classList.toggle('favorited', active);
    var ico = btn.querySelector('i');
    if (ico) { ico.className = active ? 'fas fa-bookmark' : 'far fa-bookmark'; }
  });
}

/* ══════════════════════════════════════════
   FAVORIS — SERVICES
══════════════════════════════════════════ */
function _savedSvcsKey() {
  return _currentUser ? 'gw_saved_svcs_' + _currentUser.email : null;
}
function getSavedSvcs() {
  var k = _savedSvcsKey(); if (!k) return [];
  return JSON.parse(localStorage.getItem(k) || '[]');
}
function _saveSavedSvcs(list) {
  var k = _savedSvcsKey(); if (!k) return;
  localStorage.setItem(k, JSON.stringify(list));
}
function isSvcSaved(svcId, ownerEmail) {
  return getSavedSvcs().some(function(s) { return s.svcId === svcId && s.ownerEmail === ownerEmail; });
}
function toggleSavedSvc(svcId, ownerEmail, btnEl) {
  if (!_currentUser) { showToast('Connectez-vous pour sauvegarder', 'err'); return; }
  if (ownerEmail === _currentUser.email) { showToast('C\'est votre propre service', ''); return; }
  var list = getSavedSvcs();
  var idx  = -1;
  for (var i = 0; i < list.length; i++) {
    if (list[i].svcId === svcId && list[i].ownerEmail === ownerEmail) { idx = i; break; }
  }
  if (idx !== -1) {
    list.splice(idx, 1);
    _saveSavedSvcs(list);
    if (btnEl) { btnEl.classList.remove('saved'); btnEl.querySelector('i').className = 'far fa-heart'; }
    showToast('Retiré des favoris', '');
  } else {
    list.unshift({ svcId: svcId, ownerEmail: ownerEmail, savedAt: Date.now() });
    _saveSavedSvcs(list);
    if (btnEl) { btnEl.classList.add('saved'); btnEl.querySelector('i').className = 'fas fa-heart'; }
    showToast('Service ajouté aux favoris ✓', 'ok');
  }
}

